const UCAT_QUESTIONS = [
  {"id":"ucat-vr-001","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p1","stimulus":{"kind":"text","content":"The routine use of antibiotics in livestock farming has long been defended on economic grounds: low doses added to feed accelerate growth and suppress infection in crowded conditions, lowering the cost of meat. Critics counter that this practice is a principal driver of antimicrobial resistance, since constant low-level exposure selects for resistant bacteria that can, in principle, transfer to humans. The evidence is contested. Several European countries that banned growth-promoting antibiotics in the early 2000s saw resistance in animal populations fall without the collapse in productivity that producers had predicted, though veterinary use of antibiotics to treat sick animals rose temporarily. A frequently cited difficulty is that resistance genes circulate among bacteria in soil, water and wildlife, making it hard to attribute any particular human infection to farm use specifically. What most researchers now accept is narrower but still significant: reducing agricultural antibiotic use lowers resistance in animals and in farm workers, even if the wider effect on the general population remains difficult to quantify."},"stem":"Statement: European bans on growth-promoting antibiotics caused the collapse in productivity that producers had predicted.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage says resistance fell 'without the collapse in productivity that producers had predicted', so the statement is contradicted and therefore false.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-002","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p1","stimulus":{"kind":"text","content":"The routine use of antibiotics in livestock farming has long been defended on economic grounds: low doses added to feed accelerate growth and suppress infection in crowded conditions, lowering the cost of meat. Critics counter that this practice is a principal driver of antimicrobial resistance, since constant low-level exposure selects for resistant bacteria that can, in principle, transfer to humans. The evidence is contested. Several European countries that banned growth-promoting antibiotics in the early 2000s saw resistance in animal populations fall without the collapse in productivity that producers had predicted, though veterinary use of antibiotics to treat sick animals rose temporarily. A frequently cited difficulty is that resistance genes circulate among bacteria in soil, water and wildlife, making it hard to attribute any particular human infection to farm use specifically. What most researchers now accept is narrower but still significant: reducing agricultural antibiotic use lowers resistance in animals and in farm workers, even if the wider effect on the general population remains difficult to quantify."},"stem":"Statement: It is straightforward to attribute a specific human infection to antibiotic use on a particular farm.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage calls this a 'frequently cited difficulty' because resistance genes circulate widely, so attribution is hard, not straightforward. The statement is false.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-003","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p1","stimulus":{"kind":"text","content":"The routine use of antibiotics in livestock farming has long been defended on economic grounds: low doses added to feed accelerate growth and suppress infection in crowded conditions, lowering the cost of meat. Critics counter that this practice is a principal driver of antimicrobial resistance, since constant low-level exposure selects for resistant bacteria that can, in principle, transfer to humans. The evidence is contested. Several European countries that banned growth-promoting antibiotics in the early 2000s saw resistance in animal populations fall without the collapse in productivity that producers had predicted, though veterinary use of antibiotics to treat sick animals rose temporarily. A frequently cited difficulty is that resistance genes circulate among bacteria in soil, water and wildlife, making it hard to attribute any particular human infection to farm use specifically. What most researchers now accept is narrower but still significant: reducing agricultural antibiotic use lowers resistance in animals and in farm workers, even if the wider effect on the general population remains difficult to quantify."},"stem":"Which statement is best supported by the passage?","format":"single_best","options":["Reducing farm antibiotic use reliably lowers resistance in animals and farm workers.","Banning agricultural antibiotics has no measurable effect of any kind.","Antimicrobial resistance is caused solely by livestock farming.","Producers were proven right that bans would devastate productivity."],"answer":0,"explanation":"The closing sentence states the 'narrower but still significant' consensus: reducing use lowers resistance in animals and farm workers. The other options overstate or are contradicted.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-004","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p1","stimulus":{"kind":"text","content":"The routine use of antibiotics in livestock farming has long been defended on economic grounds: low doses added to feed accelerate growth and suppress infection in crowded conditions, lowering the cost of meat. Critics counter that this practice is a principal driver of antimicrobial resistance, since constant low-level exposure selects for resistant bacteria that can, in principle, transfer to humans. The evidence is contested. Several European countries that banned growth-promoting antibiotics in the early 2000s saw resistance in animal populations fall without the collapse in productivity that producers had predicted, though veterinary use of antibiotics to treat sick animals rose temporarily. A frequently cited difficulty is that resistance genes circulate among bacteria in soil, water and wildlife, making it hard to attribute any particular human infection to farm use specifically. What most researchers now accept is narrower but still significant: reducing agricultural antibiotic use lowers resistance in animals and in farm workers, even if the wider effect on the general population remains difficult to quantify."},"stem":"The author's overall stance towards the claim that farm antibiotic use harms human health can best be described as:","format":"single_best","options":["convinced the link to the general population is fully proven","cautious, accepting a limited link while noting the wider effect is hard to quantify","dismissive of any connection between farm use and resistance","primarily concerned with defending the economic case for farmers"],"answer":1,"explanation":"The author accepts a limited, evidenced link (animals and farm workers) but repeatedly stresses the wider population effect is 'difficult to quantify', which is a cautious, qualified stance.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-005","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p2","stimulus":{"kind":"text","content":"Debates about raising the minimum wage often proceed as though the economics were settled, when in fact they are not. The textbook prediction is simple: raise the price of labour and employers will buy less of it, so unemployment among low-paid workers should rise. Yet a large body of empirical work, beginning with studies of neighbouring regions on either side of a state border, has repeatedly failed to find the predicted job losses, at least for moderate increases. Several explanations have been offered. Employers may have some power to set wages below the competitive level, so a mandated rise simply recovers ground for workers without reducing hiring. Higher wages may reduce costly staff turnover, partly paying for themselves. None of this implies that any increase, however large, would be harmless; a minimum wage set far above local productivity would almost certainly cost jobs. The honest summary is that the employment effect of modest increases appears small, while the effect of very large increases remains genuinely uncertain."},"stem":"Statement: The textbook model predicts that raising the minimum wage reduces demand for low-paid labour.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":0,"explanation":"The passage states the textbook prediction directly: raise the price of labour and employers buy less of it. The statement is true.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-006","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p2","stimulus":{"kind":"text","content":"Debates about raising the minimum wage often proceed as though the economics were settled, when in fact they are not. The textbook prediction is simple: raise the price of labour and employers will buy less of it, so unemployment among low-paid workers should rise. Yet a large body of empirical work, beginning with studies of neighbouring regions on either side of a state border, has repeatedly failed to find the predicted job losses, at least for moderate increases. Several explanations have been offered. Employers may have some power to set wages below the competitive level, so a mandated rise simply recovers ground for workers without reducing hiring. Higher wages may reduce costly staff turnover, partly paying for themselves. None of this implies that any increase, however large, would be harmless; a minimum wage set far above local productivity would almost certainly cost jobs. The honest summary is that the employment effect of modest increases appears small, while the effect of very large increases remains genuinely uncertain."},"stem":"According to the passage, one reason a wage rise might not reduce hiring is that:","format":"single_best","options":["low-paid workers do not respond to wages","minimum wages are never enforced","employers may have power to set wages below the competitive level","productivity always rises to match any wage"],"answer":2,"explanation":"The passage offers employer wage-setting power as an explanation: a mandated rise can recover ground for workers without reducing hiring. The other options are not given.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-007","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p2","stimulus":{"kind":"text","content":"Debates about raising the minimum wage often proceed as though the economics were settled, when in fact they are not. The textbook prediction is simple: raise the price of labour and employers will buy less of it, so unemployment among low-paid workers should rise. Yet a large body of empirical work, beginning with studies of neighbouring regions on either side of a state border, has repeatedly failed to find the predicted job losses, at least for moderate increases. Several explanations have been offered. Employers may have some power to set wages below the competitive level, so a mandated rise simply recovers ground for workers without reducing hiring. Higher wages may reduce costly staff turnover, partly paying for themselves. None of this implies that any increase, however large, would be harmless; a minimum wage set far above local productivity would almost certainly cost jobs. The honest summary is that the employment effect of modest increases appears small, while the effect of very large increases remains genuinely uncertain."},"stem":"Which statement would the author most likely endorse?","format":"single_best","options":["Any minimum wage increase is harmless regardless of size.","The economics of the minimum wage are fully settled.","Studies of bordering regions proved large increases are safe.","Modest increases seem to cost few jobs, but very large ones are a real risk."],"answer":3,"explanation":"The closing 'honest summary' is exactly this: small effect for modest rises, genuine uncertainty for very large ones. Option A and B are explicitly rejected; D overstates the border studies.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-008","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p2","stimulus":{"kind":"text","content":"Debates about raising the minimum wage often proceed as though the economics were settled, when in fact they are not. The textbook prediction is simple: raise the price of labour and employers will buy less of it, so unemployment among low-paid workers should rise. Yet a large body of empirical work, beginning with studies of neighbouring regions on either side of a state border, has repeatedly failed to find the predicted job losses, at least for moderate increases. Several explanations have been offered. Employers may have some power to set wages below the competitive level, so a mandated rise simply recovers ground for workers without reducing hiring. Higher wages may reduce costly staff turnover, partly paying for themselves. None of this implies that any increase, however large, would be harmless; a minimum wage set far above local productivity would almost certainly cost jobs. The honest summary is that the employment effect of modest increases appears small, while the effect of very large increases remains genuinely uncertain."},"stem":"Statement: A minimum wage set far above local productivity would have no effect on employment.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage says such a wage 'would almost certainly cost jobs', so claiming no effect is false.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-009","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p3","stimulus":{"kind":"text","content":"For two centuries, engineers dismissed Roman concrete as inferior to the modern Portland cement that replaced it. Modern concrete is stronger when first poured, but it degrades, especially in seawater, where Roman harbour structures have survived for two thousand years. Recent analysis suggests the durability is not accidental. Roman builders mixed quicklime with volcanic ash and seawater; the reaction left tiny lime-rich deposits through the material. When cracks later formed and seawater seeped in, these deposits dissolved and recrystallised, sealing the crack before it could spread. In effect the material healed itself. Researchers caution against romanticising the result. The Romans did not understand the chemistry and could not reproduce it reliably; many of their structures did fail. Reproducing the self-healing property in a modern mix that also meets contemporary strength and setting-time requirements has proved difficult, and the volcanic ash the Romans used is not available everywhere. Still, the work has redirected attention towards concretes designed to repair themselves rather than merely to resist cracking."},"stem":"Which of the following is best supported by the passage?","format":"single_best","options":["Lime-rich deposits in Roman concrete could reseal cracks that formed later.","Roman concrete is stronger than modern concrete when first poured.","The Romans deliberately engineered a self-healing material they understood.","Modern concrete never degrades in seawater."],"answer":0,"explanation":"The passage explains that the lime deposits dissolved and recrystallised to seal cracks. A is contradicted (modern is stronger when poured), C is denied (they did not understand it), D is contradicted.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-010","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p3","stimulus":{"kind":"text","content":"For two centuries, engineers dismissed Roman concrete as inferior to the modern Portland cement that replaced it. Modern concrete is stronger when first poured, but it degrades, especially in seawater, where Roman harbour structures have survived for two thousand years. Recent analysis suggests the durability is not accidental. Roman builders mixed quicklime with volcanic ash and seawater; the reaction left tiny lime-rich deposits through the material. When cracks later formed and seawater seeped in, these deposits dissolved and recrystallised, sealing the crack before it could spread. In effect the material healed itself. Researchers caution against romanticising the result. The Romans did not understand the chemistry and could not reproduce it reliably; many of their structures did fail. Reproducing the self-healing property in a modern mix that also meets contemporary strength and setting-time requirements has proved difficult, and the volcanic ash the Romans used is not available everywhere. Still, the work has redirected attention towards concretes designed to repair themselves rather than merely to resist cracking."},"stem":"Statement: All Roman concrete structures have survived to the present day.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage notes 'many of their structures did fail', so the universal claim is false.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-011","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p3","stimulus":{"kind":"text","content":"For two centuries, engineers dismissed Roman concrete as inferior to the modern Portland cement that replaced it. Modern concrete is stronger when first poured, but it degrades, especially in seawater, where Roman harbour structures have survived for two thousand years. Recent analysis suggests the durability is not accidental. Roman builders mixed quicklime with volcanic ash and seawater; the reaction left tiny lime-rich deposits through the material. When cracks later formed and seawater seeped in, these deposits dissolved and recrystallised, sealing the crack before it could spread. In effect the material healed itself. Researchers caution against romanticising the result. The Romans did not understand the chemistry and could not reproduce it reliably; many of their structures did fail. Reproducing the self-healing property in a modern mix that also meets contemporary strength and setting-time requirements has proved difficult, and the volcanic ash the Romans used is not available everywhere. Still, the work has redirected attention towards concretes designed to repair themselves rather than merely to resist cracking."},"stem":"Statement: The volcanic ash used by Roman builders is freely available in every region today.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage says the ash 'is not available everywhere', contradicting the statement, so it is false.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-012","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p3","stimulus":{"kind":"text","content":"For two centuries, engineers dismissed Roman concrete as inferior to the modern Portland cement that replaced it. Modern concrete is stronger when first poured, but it degrades, especially in seawater, where Roman harbour structures have survived for two thousand years. Recent analysis suggests the durability is not accidental. Roman builders mixed quicklime with volcanic ash and seawater; the reaction left tiny lime-rich deposits through the material. When cracks later formed and seawater seeped in, these deposits dissolved and recrystallised, sealing the crack before it could spread. In effect the material healed itself. Researchers caution against romanticising the result. The Romans did not understand the chemistry and could not reproduce it reliably; many of their structures did fail. Reproducing the self-healing property in a modern mix that also meets contemporary strength and setting-time requirements has proved difficult, and the volcanic ash the Romans used is not available everywhere. Still, the work has redirected attention towards concretes designed to repair themselves rather than merely to resist cracking."},"stem":"Why do the researchers 'caution against romanticising the result'?","format":"single_best","options":["because Roman concrete was never used in harbours","because the Romans could not reproduce the effect reliably and many structures failed","because the Romans understood the chemistry perfectly","because modern concrete is self-healing already"],"answer":1,"explanation":"The caution is justified by the points that the Romans did not understand the chemistry, could not reproduce it reliably, and many structures failed.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-013","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p4","stimulus":{"kind":"text","content":"Many songbird species do not inherit their songs fully formed; they learn them, and as a result regional 'dialects' emerge. A young male typically learns from adult males nearby during a sensitive period early in life, after which the song crystallises and changes little. Because learning is local, neighbouring populations can diverge, and a bird raised in isolation produces only an abnormal, simplified song. Field recordings show that dialect boundaries can be remarkably sharp, sometimes shifting over a few kilometres. The function of these dialects is debated. One hypothesis holds that females prefer local songs, so that dialect acts as a marker of local adaptation; another holds that dialects are simply a by-product of imperfect copying with no function of their own. Crucially, the evidence does not yet decisively favour either view, and the two are not mutually exclusive. What is clear is that song is cultural in the limited sense that it is transmitted by learning across generations rather than carried in the genes alone."},"stem":"Statement: A songbird raised in isolation will still develop a fully normal song.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage says an isolated bird produces 'only an abnormal, simplified song', so the statement is false.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-014","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p4","stimulus":{"kind":"text","content":"Many songbird species do not inherit their songs fully formed; they learn them, and as a result regional 'dialects' emerge. A young male typically learns from adult males nearby during a sensitive period early in life, after which the song crystallises and changes little. Because learning is local, neighbouring populations can diverge, and a bird raised in isolation produces only an abnormal, simplified song. Field recordings show that dialect boundaries can be remarkably sharp, sometimes shifting over a few kilometres. The function of these dialects is debated. One hypothesis holds that females prefer local songs, so that dialect acts as a marker of local adaptation; another holds that dialects are simply a by-product of imperfect copying with no function of their own. Crucially, the evidence does not yet decisively favour either view, and the two are not mutually exclusive. What is clear is that song is cultural in the limited sense that it is transmitted by learning across generations rather than carried in the genes alone."},"stem":"Which statement about birdsong dialects is best supported?","format":"single_best","options":["The evidence decisively shows females prefer local dialects.","Song is carried entirely in the genes.","Dialects can have sharp boundaries and may arise because song is learned locally.","Dialects are known to serve no function at all."],"answer":2,"explanation":"The passage states boundaries can be sharp and that local learning drives divergence. It explicitly says the evidence does not decisively favour the female-preference or the by-product view, ruling out A and D; C is contradicted.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-015","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p4","stimulus":{"kind":"text","content":"Many songbird species do not inherit their songs fully formed; they learn them, and as a result regional 'dialects' emerge. A young male typically learns from adult males nearby during a sensitive period early in life, after which the song crystallises and changes little. Because learning is local, neighbouring populations can diverge, and a bird raised in isolation produces only an abnormal, simplified song. Field recordings show that dialect boundaries can be remarkably sharp, sometimes shifting over a few kilometres. The function of these dialects is debated. One hypothesis holds that females prefer local songs, so that dialect acts as a marker of local adaptation; another holds that dialects are simply a by-product of imperfect copying with no function of their own. Crucially, the evidence does not yet decisively favour either view, and the two are not mutually exclusive. What is clear is that song is cultural in the limited sense that it is transmitted by learning across generations rather than carried in the genes alone."},"stem":"In the passage, the claim that song is 'cultural' is best understood to mean that:","format":"single_best","options":["song is identical in every population","song has no biological basis whatsoever","only humans influence how birds sing","song is transmitted by learning across generations rather than by genes alone"],"answer":3,"explanation":"The final sentence defines the limited sense of 'cultural' as transmission by learning across generations rather than carried in the genes alone.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-016","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p4","stimulus":{"kind":"text","content":"Many songbird species do not inherit their songs fully formed; they learn them, and as a result regional 'dialects' emerge. A young male typically learns from adult males nearby during a sensitive period early in life, after which the song crystallises and changes little. Because learning is local, neighbouring populations can diverge, and a bird raised in isolation produces only an abnormal, simplified song. Field recordings show that dialect boundaries can be remarkably sharp, sometimes shifting over a few kilometres. The function of these dialects is debated. One hypothesis holds that females prefer local songs, so that dialect acts as a marker of local adaptation; another holds that dialects are simply a by-product of imperfect copying with no function of their own. Crucially, the evidence does not yet decisively favour either view, and the two are not mutually exclusive. What is clear is that song is cultural in the limited sense that it is transmitted by learning across generations rather than carried in the genes alone."},"stem":"Statement: The hypotheses that dialects signal local adaptation and that they are a by-product of copying cannot both be partly true.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage states the two views 'are not mutually exclusive', so claiming they cannot both be partly true is false.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-017","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p5","stimulus":{"kind":"text","content":"Psychology has spent the past decade confronting a 'replication crisis': when researchers repeated well-known experiments, a substantial fraction of the original findings did not hold up. The causes are now reasonably well understood. Studies were often small, giving results that fluctuated by chance; journals preferred to publish striking positive findings over null results; and flexible analysis allowed researchers, often unconsciously, to keep testing until something reached significance. None of this requires deliberate fraud, which remains rare. The response has been largely constructive. Many journals now encourage pre-registration, in which the hypothesis and analysis plan are fixed before data are collected, and large multi-laboratory collaborations have repeated key studies at scale. Critics warn against overcorrection: a finding that fails one replication is not thereby proven false, since the repeat may differ in subtle ways, and a culture too hostile to exploratory work could discourage genuine discovery. The emerging consensus is that the crisis, though real, has prompted reforms likely to leave the field more reliable than before."},"stem":"Which of the following does the passage identify as a cause of the replication crisis?","format":"single_best","options":["a preference for publishing striking positive results over null results","widespread deliberate fraud","the abolition of pre-registration","the use of overly large samples"],"answer":0,"explanation":"Publication bias toward striking positive findings is listed as a cause. Fraud is said to be rare, samples were small not large, and pre-registration is a response not a cause.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-018","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p5","stimulus":{"kind":"text","content":"Psychology has spent the past decade confronting a 'replication crisis': when researchers repeated well-known experiments, a substantial fraction of the original findings did not hold up. The causes are now reasonably well understood. Studies were often small, giving results that fluctuated by chance; journals preferred to publish striking positive findings over null results; and flexible analysis allowed researchers, often unconsciously, to keep testing until something reached significance. None of this requires deliberate fraud, which remains rare. The response has been largely constructive. Many journals now encourage pre-registration, in which the hypothesis and analysis plan are fixed before data are collected, and large multi-laboratory collaborations have repeated key studies at scale. Critics warn against overcorrection: a finding that fails one replication is not thereby proven false, since the repeat may differ in subtle ways, and a culture too hostile to exploratory work could discourage genuine discovery. The emerging consensus is that the crisis, though real, has prompted reforms likely to leave the field more reliable than before."},"stem":"Statement: According to the passage, a single failed replication proves the original finding false.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage warns that 'a finding that fails one replication is not thereby proven false', so the statement is false.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-019","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p5","stimulus":{"kind":"text","content":"Psychology has spent the past decade confronting a 'replication crisis': when researchers repeated well-known experiments, a substantial fraction of the original findings did not hold up. The causes are now reasonably well understood. Studies were often small, giving results that fluctuated by chance; journals preferred to publish striking positive findings over null results; and flexible analysis allowed researchers, often unconsciously, to keep testing until something reached significance. None of this requires deliberate fraud, which remains rare. The response has been largely constructive. Many journals now encourage pre-registration, in which the hypothesis and analysis plan are fixed before data are collected, and large multi-laboratory collaborations have repeated key studies at scale. Critics warn against overcorrection: a finding that fails one replication is not thereby proven false, since the repeat may differ in subtle ways, and a culture too hostile to exploratory work could discourage genuine discovery. The emerging consensus is that the crisis, though real, has prompted reforms likely to leave the field more reliable than before."},"stem":"Statement: Deliberate fraud is described as the main driver of the crisis.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage says fraud 'remains rare' and lists other causes, so it is not the main driver; the statement is false.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-020","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p5","stimulus":{"kind":"text","content":"Psychology has spent the past decade confronting a 'replication crisis': when researchers repeated well-known experiments, a substantial fraction of the original findings did not hold up. The causes are now reasonably well understood. Studies were often small, giving results that fluctuated by chance; journals preferred to publish striking positive findings over null results; and flexible analysis allowed researchers, often unconsciously, to keep testing until something reached significance. None of this requires deliberate fraud, which remains rare. The response has been largely constructive. Many journals now encourage pre-registration, in which the hypothesis and analysis plan are fixed before data are collected, and large multi-laboratory collaborations have repeated key studies at scale. Critics warn against overcorrection: a finding that fails one replication is not thereby proven false, since the repeat may differ in subtle ways, and a culture too hostile to exploratory work could discourage genuine discovery. The emerging consensus is that the crisis, though real, has prompted reforms likely to leave the field more reliable than before."},"stem":"The author's attitude to the reforms prompted by the crisis is best described as:","format":"single_best","options":["entirely hostile to pre-registration","broadly positive while warning against overcorrection","convinced the field is now beyond improvement","indifferent to whether psychology is reliable"],"answer":1,"explanation":"The author calls the response 'largely constructive' and expects a more reliable field, while explicitly cautioning against overcorrection. That is broadly positive with a caveat.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-021","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p6","stimulus":{"kind":"text","content":"Cities are measurably hotter than the countryside around them, a phenomenon known as the urban heat island. Dark roofs and roads absorb sunlight, dense construction traps heat, and the loss of vegetation removes the cooling that comes from plants releasing water vapour. The effect is strongest at night, when rural areas cool quickly but built-up areas release stored heat slowly. The consequences are not evenly shared: low-income neighbourhoods tend to have less tree cover and less air conditioning, so they bear more of the health burden during heatwaves. Proposed remedies include painting roofs with reflective coatings, planting street trees, and creating parks, though each has limits. Reflective roofs cut daytime cooling costs but do little at night; trees take years to mature and require water that may be scarce in exactly the hot, dry cities that need them most. The most effective strategies tend to combine measures rather than relying on any single fix, and to direct resources first to the neighbourhoods that are most exposed."},"stem":"Statement: The urban heat island effect is described as strongest at night.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":0,"explanation":"The passage states the effect 'is strongest at night', so the statement is true.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-022","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p6","stimulus":{"kind":"text","content":"Cities are measurably hotter than the countryside around them, a phenomenon known as the urban heat island. Dark roofs and roads absorb sunlight, dense construction traps heat, and the loss of vegetation removes the cooling that comes from plants releasing water vapour. The effect is strongest at night, when rural areas cool quickly but built-up areas release stored heat slowly. The consequences are not evenly shared: low-income neighbourhoods tend to have less tree cover and less air conditioning, so they bear more of the health burden during heatwaves. Proposed remedies include painting roofs with reflective coatings, planting street trees, and creating parks, though each has limits. Reflective roofs cut daytime cooling costs but do little at night; trees take years to mature and require water that may be scarce in exactly the hot, dry cities that need them most. The most effective strategies tend to combine measures rather than relying on any single fix, and to direct resources first to the neighbourhoods that are most exposed."},"stem":"Which statement is best supported by the passage?","format":"single_best","options":["Reflective roofs solve the heat island problem on their own.","Planting trees provides instant cooling everywhere.","The health burden of urban heat falls disproportionately on low-income neighbourhoods.","Rural areas retain heat longer than cities at night."],"answer":2,"explanation":"The passage states low-income areas have less tree cover and air conditioning and bear more of the health burden. Reflective roofs and trees are each said to have limits, and rural areas cool faster, not slower.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-023","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p6","stimulus":{"kind":"text","content":"Cities are measurably hotter than the countryside around them, a phenomenon known as the urban heat island. Dark roofs and roads absorb sunlight, dense construction traps heat, and the loss of vegetation removes the cooling that comes from plants releasing water vapour. The effect is strongest at night, when rural areas cool quickly but built-up areas release stored heat slowly. The consequences are not evenly shared: low-income neighbourhoods tend to have less tree cover and less air conditioning, so they bear more of the health burden during heatwaves. Proposed remedies include painting roofs with reflective coatings, planting street trees, and creating parks, though each has limits. Reflective roofs cut daytime cooling costs but do little at night; trees take years to mature and require water that may be scarce in exactly the hot, dry cities that need them most. The most effective strategies tend to combine measures rather than relying on any single fix, and to direct resources first to the neighbourhoods that are most exposed."},"stem":"Statement: Street trees can be planted in any hot city without difficulty.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage notes trees take years to mature and need water that may be scarce in hot, dry cities, so the statement is false.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-024","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p6","stimulus":{"kind":"text","content":"Cities are measurably hotter than the countryside around them, a phenomenon known as the urban heat island. Dark roofs and roads absorb sunlight, dense construction traps heat, and the loss of vegetation removes the cooling that comes from plants releasing water vapour. The effect is strongest at night, when rural areas cool quickly but built-up areas release stored heat slowly. The consequences are not evenly shared: low-income neighbourhoods tend to have less tree cover and less air conditioning, so they bear more of the health burden during heatwaves. Proposed remedies include painting roofs with reflective coatings, planting street trees, and creating parks, though each has limits. Reflective roofs cut daytime cooling costs but do little at night; trees take years to mature and require water that may be scarce in exactly the hot, dry cities that need them most. The most effective strategies tend to combine measures rather than relying on any single fix, and to direct resources first to the neighbourhoods that are most exposed."},"stem":"The passage suggests the most effective response to urban heat is to:","format":"single_best","options":["rely on a single, cheap measure applied uniformly","abandon street trees entirely","focus only on daytime cooling costs","combine measures and prioritise the most exposed neighbourhoods"],"answer":3,"explanation":"The final sentence recommends combining measures and directing resources first to the most exposed neighbourhoods.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-025","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p7","stimulus":{"kind":"text","content":"The spread of the printing press in fifteenth-century Europe is often credited with causing the rise in literacy that followed, but the relationship was more tangled than that. Printing made books dramatically cheaper, which certainly mattered, yet for decades most printed works were in Latin and aimed at a small, already-literate clerical readership. Mass literacy depended on other developments: the gradual shift to printing in local languages, the growth of schools, and, in some regions, religious movements that urged ordinary believers to read scripture for themselves. Printing also did things unrelated to literacy. It standardised texts, so that two copies of a book could be assumed identical, which transformed scholarship and law. It accelerated the circulation of news and rumour alike, and it gave authorities a new technology to control through licensing and censorship. Historians therefore tend to describe the press not as a single cause of social change but as an amplifier that made existing trends faster and harder to reverse."},"stem":"Statement: In the decades after its spread, most printed works were in local languages aimed at ordinary readers.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage says most printed works 'were in Latin and aimed at a small, already-literate clerical readership', so the statement is false.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-026","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p7","stimulus":{"kind":"text","content":"The spread of the printing press in fifteenth-century Europe is often credited with causing the rise in literacy that followed, but the relationship was more tangled than that. Printing made books dramatically cheaper, which certainly mattered, yet for decades most printed works were in Latin and aimed at a small, already-literate clerical readership. Mass literacy depended on other developments: the gradual shift to printing in local languages, the growth of schools, and, in some regions, religious movements that urged ordinary believers to read scripture for themselves. Printing also did things unrelated to literacy. It standardised texts, so that two copies of a book could be assumed identical, which transformed scholarship and law. It accelerated the circulation of news and rumour alike, and it gave authorities a new technology to control through licensing and censorship. Historians therefore tend to describe the press not as a single cause of social change but as an amplifier that made existing trends faster and harder to reverse."},"stem":"Which statement best captures the passage's view of the printing press?","format":"single_best","options":["It acted as an amplifier of existing trends rather than a single cause.","It was the sole cause of rising literacy.","It had no effect on scholarship or law.","It made censorship impossible."],"answer":0,"explanation":"The closing sentence describes the press as 'an amplifier that made existing trends faster', not a single cause. The other options are each contradicted.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-027","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p7","stimulus":{"kind":"text","content":"The spread of the printing press in fifteenth-century Europe is often credited with causing the rise in literacy that followed, but the relationship was more tangled than that. Printing made books dramatically cheaper, which certainly mattered, yet for decades most printed works were in Latin and aimed at a small, already-literate clerical readership. Mass literacy depended on other developments: the gradual shift to printing in local languages, the growth of schools, and, in some regions, religious movements that urged ordinary believers to read scripture for themselves. Printing also did things unrelated to literacy. It standardised texts, so that two copies of a book could be assumed identical, which transformed scholarship and law. It accelerated the circulation of news and rumour alike, and it gave authorities a new technology to control through licensing and censorship. Historians therefore tend to describe the press not as a single cause of social change but as an amplifier that made existing trends faster and harder to reverse."},"stem":"According to the passage, one effect of printing unrelated to literacy was that it:","format":"single_best","options":["guaranteed every citizen learned to read","standardised texts so copies could be assumed identical","eliminated all rumour from circulation","ended the use of Latin overnight"],"answer":1,"explanation":"The passage gives standardisation of texts as an effect that transformed scholarship and law, distinct from literacy.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-028","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p7","stimulus":{"kind":"text","content":"The spread of the printing press in fifteenth-century Europe is often credited with causing the rise in literacy that followed, but the relationship was more tangled than that. Printing made books dramatically cheaper, which certainly mattered, yet for decades most printed works were in Latin and aimed at a small, already-literate clerical readership. Mass literacy depended on other developments: the gradual shift to printing in local languages, the growth of schools, and, in some regions, religious movements that urged ordinary believers to read scripture for themselves. Printing also did things unrelated to literacy. It standardised texts, so that two copies of a book could be assumed identical, which transformed scholarship and law. It accelerated the circulation of news and rumour alike, and it gave authorities a new technology to control through licensing and censorship. Historians therefore tend to describe the press not as a single cause of social change but as an amplifier that made existing trends faster and harder to reverse."},"stem":"Statement: Printing gave authorities new tools for licensing and censorship.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":0,"explanation":"The passage states printing 'gave authorities a new technology to control through licensing and censorship', so the statement is true.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-029","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p8","stimulus":{"kind":"text","content":"Governments increasingly use 'nudges', small changes to how choices are presented, to influence behaviour without banning anything or changing prices. Automatically enrolling employees in a pension scheme while letting them opt out, for example, sharply raises participation compared with asking them to opt in, even though the options are identical. Advocates argue that nudges are cheap, preserve freedom of choice, and simply counteract the predictable biases that lead people to act against their own stated goals. Sceptics raise two objections. The first is practical: some nudges produce effects that are small or that fade once the novelty passes. The second is ethical: a nudge works precisely because people do not fully notice it, which sits awkwardly with the idea of respecting their autonomy. Defenders reply that the alternative is not a neutral world but one in which choices are already framed in some way, often by businesses pursuing their own ends; the only question is whether that framing is designed thoughtfully. The debate, in short, is less about whether to influence behaviour than about who should do the influencing, and how openly."},"stem":"Which statement is best supported by the passage?","format":"single_best","options":["Automatic enrolment lowers pension participation.","Nudges always produce large, lasting effects.","Default options can change behaviour even when the choices themselves are identical.","Every nudge is openly disclosed to those it affects."],"answer":2,"explanation":"The pension example shows defaults shifting participation though the options are identical. B follows; A reverses it; C and D are contradicted by the sceptics' points.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-030","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p8","stimulus":{"kind":"text","content":"Governments increasingly use 'nudges', small changes to how choices are presented, to influence behaviour without banning anything or changing prices. Automatically enrolling employees in a pension scheme while letting them opt out, for example, sharply raises participation compared with asking them to opt in, even though the options are identical. Advocates argue that nudges are cheap, preserve freedom of choice, and simply counteract the predictable biases that lead people to act against their own stated goals. Sceptics raise two objections. The first is practical: some nudges produce effects that are small or that fade once the novelty passes. The second is ethical: a nudge works precisely because people do not fully notice it, which sits awkwardly with the idea of respecting their autonomy. Defenders reply that the alternative is not a neutral world but one in which choices are already framed in some way, often by businesses pursuing their own ends; the only question is whether that framing is designed thoughtfully. The debate, in short, is less about whether to influence behaviour than about who should do the influencing, and how openly."},"stem":"Statement: The passage claims all nudges produce only short-lived effects.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage says 'some nudges' fade, not all, so the universal claim is false.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-031","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p8","stimulus":{"kind":"text","content":"Governments increasingly use 'nudges', small changes to how choices are presented, to influence behaviour without banning anything or changing prices. Automatically enrolling employees in a pension scheme while letting them opt out, for example, sharply raises participation compared with asking them to opt in, even though the options are identical. Advocates argue that nudges are cheap, preserve freedom of choice, and simply counteract the predictable biases that lead people to act against their own stated goals. Sceptics raise two objections. The first is practical: some nudges produce effects that are small or that fade once the novelty passes. The second is ethical: a nudge works precisely because people do not fully notice it, which sits awkwardly with the idea of respecting their autonomy. Defenders reply that the alternative is not a neutral world but one in which choices are already framed in some way, often by businesses pursuing their own ends; the only question is whether that framing is designed thoughtfully. The debate, in short, is less about whether to influence behaviour than about who should do the influencing, and how openly."},"stem":"The defenders' reply to the ethical objection is that:","format":"single_best","options":["nudges are always noticed by those affected","businesses never influence consumer choices","autonomy is unimportant","there is no neutral alternative, since choices are already framed by someone"],"answer":3,"explanation":"Defenders argue the alternative is not a neutral world but one already framed by others, so the real question is who frames choices and how thoughtfully.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-032","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p8","stimulus":{"kind":"text","content":"Governments increasingly use 'nudges', small changes to how choices are presented, to influence behaviour without banning anything or changing prices. Automatically enrolling employees in a pension scheme while letting them opt out, for example, sharply raises participation compared with asking them to opt in, even though the options are identical. Advocates argue that nudges are cheap, preserve freedom of choice, and simply counteract the predictable biases that lead people to act against their own stated goals. Sceptics raise two objections. The first is practical: some nudges produce effects that are small or that fade once the novelty passes. The second is ethical: a nudge works precisely because people do not fully notice it, which sits awkwardly with the idea of respecting their autonomy. Defenders reply that the alternative is not a neutral world but one in which choices are already framed in some way, often by businesses pursuing their own ends; the only question is whether that framing is designed thoughtfully. The debate, in short, is less about whether to influence behaviour than about who should do the influencing, and how openly."},"stem":"Statement: The passage frames the debate as ultimately about who should influence behaviour and how openly.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":0,"explanation":"The closing sentence says the debate is 'about who should do the influencing, and how openly', so the statement is true.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-033","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p9","stimulus":{"kind":"text","content":"Interest in mining the deep seabed has grown with demand for the metals used in batteries. Vast fields of potato-sized nodules rich in cobalt, nickel and manganese lie on the abyssal plains, and unlike land deposits they can in principle be collected without digging or blasting. Supporters argue that seabed mining could supply critical metals with a smaller land footprint and without the labour abuses associated with some terrestrial mines. The ecological case against is serious. The abyssal seafloor is one of the least disturbed habitats on Earth, home to slow-growing species found nowhere else, and the plumes of sediment stirred up by collection could smother life over wide areas. Because these ecosystems take so long to recover, damage may be effectively permanent on any human timescale. A further complication is governance: much of the seabed lies beyond national jurisdiction, so any rules must be agreed internationally, a slow and contested process. Several major companies have paused their plans pending clearer regulation, while others press to begin."},"stem":"Statement: Seabed nodules can in principle be collected without digging or blasting.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":0,"explanation":"The passage states the nodules 'can in principle be collected without digging or blasting', so the statement is true.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-034","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p9","stimulus":{"kind":"text","content":"Interest in mining the deep seabed has grown with demand for the metals used in batteries. Vast fields of potato-sized nodules rich in cobalt, nickel and manganese lie on the abyssal plains, and unlike land deposits they can in principle be collected without digging or blasting. Supporters argue that seabed mining could supply critical metals with a smaller land footprint and without the labour abuses associated with some terrestrial mines. The ecological case against is serious. The abyssal seafloor is one of the least disturbed habitats on Earth, home to slow-growing species found nowhere else, and the plumes of sediment stirred up by collection could smother life over wide areas. Because these ecosystems take so long to recover, damage may be effectively permanent on any human timescale. A further complication is governance: much of the seabed lies beyond national jurisdiction, so any rules must be agreed internationally, a slow and contested process. Several major companies have paused their plans pending clearer regulation, while others press to begin."},"stem":"Which statement is best supported by the passage?","format":"single_best","options":["Sediment plumes from collection could smother life over wide areas.","Deep-sea ecosystems recover quickly from disturbance.","The entire seabed lies within national jurisdiction.","All mining companies are proceeding without hesitation."],"answer":0,"explanation":"The passage states plumes 'could smother life over wide areas'. Recovery is said to be very slow, much seabed is beyond national jurisdiction, and some companies have paused.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-035","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p9","stimulus":{"kind":"text","content":"Interest in mining the deep seabed has grown with demand for the metals used in batteries. Vast fields of potato-sized nodules rich in cobalt, nickel and manganese lie on the abyssal plains, and unlike land deposits they can in principle be collected without digging or blasting. Supporters argue that seabed mining could supply critical metals with a smaller land footprint and without the labour abuses associated with some terrestrial mines. The ecological case against is serious. The abyssal seafloor is one of the least disturbed habitats on Earth, home to slow-growing species found nowhere else, and the plumes of sediment stirred up by collection could smother life over wide areas. Because these ecosystems take so long to recover, damage may be effectively permanent on any human timescale. A further complication is governance: much of the seabed lies beyond national jurisdiction, so any rules must be agreed internationally, a slow and contested process. Several major companies have paused their plans pending clearer regulation, while others press to begin."},"stem":"The passage suggests that governance of seabed mining is difficult mainly because:","format":"single_best","options":["the metals involved are worthless","much of the seabed lies beyond any single nation's jurisdiction","no company is interested in mining","the seafloor is easy to monitor"],"answer":1,"explanation":"The passage identifies that much of the seabed is beyond national jurisdiction, so rules must be agreed internationally, which is slow and contested.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-036","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p9","stimulus":{"kind":"text","content":"Interest in mining the deep seabed has grown with demand for the metals used in batteries. Vast fields of potato-sized nodules rich in cobalt, nickel and manganese lie on the abyssal plains, and unlike land deposits they can in principle be collected without digging or blasting. Supporters argue that seabed mining could supply critical metals with a smaller land footprint and without the labour abuses associated with some terrestrial mines. The ecological case against is serious. The abyssal seafloor is one of the least disturbed habitats on Earth, home to slow-growing species found nowhere else, and the plumes of sediment stirred up by collection could smother life over wide areas. Because these ecosystems take so long to recover, damage may be effectively permanent on any human timescale. A further complication is governance: much of the seabed lies beyond national jurisdiction, so any rules must be agreed internationally, a slow and contested process. Several major companies have paused their plans pending clearer regulation, while others press to begin."},"stem":"Statement: Seabed mining is cheaper than mining on land.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":2,"explanation":"The passage discusses footprint and labour but never compares the monetary cost of seabed and land mining, so this cannot be told.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-037","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p10","stimulus":{"kind":"text","content":"Museums in wealthy countries hold many objects acquired during periods of empire, and demands for their return have grown louder. The case for repatriation is partly about justice: items taken under coercion, or outright looted, arguably belong with the communities they came from, for whom they may carry living religious or cultural meaning rather than mere historical interest. Opponents rarely defend looting, but they raise other considerations. Large encyclopaedic museums, they argue, let visitors encounter many cultures side by side, and concentrating objects in one place can aid conservation and scholarship. There are also hard practical questions about provenance: ownership histories are often incomplete, and deciding which present-day institution or community is the rightful successor to a centuries-old culture is not always straightforward. A growing number of museums have begun to navigate these tensions case by case, returning some objects, lending others, and sharing research and digital access. The trend is clearly towards greater willingness to return, even as the principles for deciding individual claims remain unsettled."},"stem":"Which statement best reflects the opponents' position as described?","format":"single_best","options":["They defend the original looting of objects.","They insist no object should ever be returned.","They raise concerns about access, conservation and provenance rather than defending looting.","They claim provenance is always perfectly documented."],"answer":2,"explanation":"The passage says opponents 'rarely defend looting' but raise encyclopaedic access, conservation and provenance difficulties. The other options misstate their view.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-038","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p10","stimulus":{"kind":"text","content":"Museums in wealthy countries hold many objects acquired during periods of empire, and demands for their return have grown louder. The case for repatriation is partly about justice: items taken under coercion, or outright looted, arguably belong with the communities they came from, for whom they may carry living religious or cultural meaning rather than mere historical interest. Opponents rarely defend looting, but they raise other considerations. Large encyclopaedic museums, they argue, let visitors encounter many cultures side by side, and concentrating objects in one place can aid conservation and scholarship. There are also hard practical questions about provenance: ownership histories are often incomplete, and deciding which present-day institution or community is the rightful successor to a centuries-old culture is not always straightforward. A growing number of museums have begun to navigate these tensions case by case, returning some objects, lending others, and sharing research and digital access. The trend is clearly towards greater willingness to return, even as the principles for deciding individual claims remain unsettled."},"stem":"Statement: The passage states that the principles for deciding individual repatriation claims are now fully settled.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":1,"explanation":"The passage says the principles 'remain unsettled', so the statement is false.","difficulty":"hard","source":"original"},
  {"id":"ucat-vr-039","subtest":"verbal_reasoning","type":"true_false_cant_tell","stimulusId":"ucat-vr-p10","stimulus":{"kind":"text","content":"Museums in wealthy countries hold many objects acquired during periods of empire, and demands for their return have grown louder. The case for repatriation is partly about justice: items taken under coercion, or outright looted, arguably belong with the communities they came from, for whom they may carry living religious or cultural meaning rather than mere historical interest. Opponents rarely defend looting, but they raise other considerations. Large encyclopaedic museums, they argue, let visitors encounter many cultures side by side, and concentrating objects in one place can aid conservation and scholarship. There are also hard practical questions about provenance: ownership histories are often incomplete, and deciding which present-day institution or community is the rightful successor to a centuries-old culture is not always straightforward. A growing number of museums have begun to navigate these tensions case by case, returning some objects, lending others, and sharing research and digital access. The trend is clearly towards greater willingness to return, even as the principles for deciding individual claims remain unsettled."},"stem":"Statement: Some museums have returned certain objects while lending or sharing access to others.","format":"true_false_cant_tell","options":["True","False","Can't tell"],"answer":0,"explanation":"The passage describes museums returning some objects, lending others, and sharing research and digital access, so the statement is true.","difficulty":"medium","source":"original"},
  {"id":"ucat-vr-040","subtest":"verbal_reasoning","type":"reading_comprehension","stimulusId":"ucat-vr-p10","stimulus":{"kind":"text","content":"Museums in wealthy countries hold many objects acquired during periods of empire, and demands for their return have grown louder. The case for repatriation is partly about justice: items taken under coercion, or outright looted, arguably belong with the communities they came from, for whom they may carry living religious or cultural meaning rather than mere historical interest. Opponents rarely defend looting, but they raise other considerations. Large encyclopaedic museums, they argue, let visitors encounter many cultures side by side, and concentrating objects in one place can aid conservation and scholarship. There are also hard practical questions about provenance: ownership histories are often incomplete, and deciding which present-day institution or community is the rightful successor to a centuries-old culture is not always straightforward. A growing number of museums have begun to navigate these tensions case by case, returning some objects, lending others, and sharing research and digital access. The trend is clearly towards greater willingness to return, even as the principles for deciding individual claims remain unsettled."},"stem":"The overall trend the passage identifies is:","format":"single_best","options":["a clear movement away from returning objects","a complete and final resolution of all claims","total refusal by museums to engage with the issue","greater willingness to return objects, though deciding individual claims remains unsettled"],"answer":3,"explanation":"The final sentences state the trend is clearly towards greater willingness to return, even as principles for individual claims remain unsettled.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-001","subtest":"decision_making","type":"syllogism","stimulusId":null,"stem":"All cardiologists are physicians. No physician at this hospital lacks a current registration. Some staff at this hospital are not physicians. Which conclusion follows logically?","format":"single_best","options":["Every cardiologist at this hospital has a current registration.","Some cardiologists lack a current registration.","All staff at this hospital are physicians.","No staff member has a current registration."],"answer":0,"explanation":"Cardiologists are physicians, and no physician at the hospital lacks registration, so every cardiologist there is registered. The other options contradict or overreach the premises.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-002","subtest":"decision_making","type":"syllogism","stimulusId":null,"stem":"No reptiles are warm-blooded. All snakes are reptiles. Some pets are snakes. Which conclusion must be true?","format":"single_best","options":["All pets are reptiles.","Some pets are not warm-blooded.","Some snakes are warm-blooded.","No pets are reptiles."],"answer":1,"explanation":"Some pets are snakes, snakes are reptiles, and no reptile is warm-blooded, so those pets are not warm-blooded. Hence some pets are not warm-blooded.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-003","subtest":"decision_making","type":"syllogism","stimulusId":null,"stem":"Everyone who passed the exam attended the revision class. Priya did not attend the revision class. Which conclusion follows?","format":"single_best","options":["Priya passed the exam.","Everyone who attended the class passed.","Priya did not pass the exam.","Only Priya failed the exam."],"answer":2,"explanation":"Passing requires attendance (passed implies attended). Priya did not attend, so by contraposition she did not pass. The converse claims in C and D do not follow.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-004","subtest":"decision_making","type":"syllogism","stimulusId":null,"stem":"Some musicians are not pianists. All pianists can read music. Which statement is definitely true?","format":"single_best","options":["No musician can read music.","All musicians are pianists.","Some pianists cannot read music.","Nothing definite follows about whether all musicians can read music."],"answer":3,"explanation":"The premises constrain pianists, not musicians in general. The musicians who are not pianists may or may not read music, so no firm conclusion about all musicians follows.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-005","subtest":"decision_making","type":"syllogism","stimulusId":null,"stem":"If a sample is contaminated, the test is repeated. The test was not repeated. Assuming the rule held, which conclusion is valid?","format":"single_best","options":["The sample was not contaminated.","The sample was contaminated.","The test was contaminated.","Every sample is contaminated."],"answer":0,"explanation":"Contaminated implies repeated. The test was not repeated, so by contraposition the sample was not contaminated.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-006","subtest":"decision_making","type":"syllogism","stimulusId":null,"stem":"All members of the committee voted. Some who voted abstained on the budget. No one who abstained on the budget is the treasurer. Which follows?","format":"single_best","options":["The treasurer is not a committee member.","The treasurer did not abstain on the budget.","Everyone who voted abstained on the budget.","No committee member voted."],"answer":1,"explanation":"No one who abstained on the budget is the treasurer, so the treasurer did not abstain on the budget. The remaining options are not entailed.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-007","subtest":"decision_making","type":"logical_puzzle","stimulusId":"ucat-dm-pz1","stimulus":{"kind":"text","content":"Five doctors (A, B, C, D, E) are each on call on exactly one day from Monday to Friday, one per day. Clues: A is on call earlier in the week than C. D is on call the day immediately after B. E is on call on Wednesday. A is not on call on Monday."},"stem":"Given the rota clues, who must be on call on Monday?","format":"single_best","options":["A","C","B","D"],"answer":2,"explanation":"E is Wednesday and A is not Monday. B is immediately before D, so the B-D pair occupies two adjacent days. The only consistent placements put B on Monday, D on Tuesday, A on Thursday, C on Friday. So B is on Monday.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-008","subtest":"decision_making","type":"logical_puzzle","stimulusId":"ucat-dm-pz1","stimulus":{"kind":"text","content":"Five doctors (A, B, C, D, E) are each on call on exactly one day from Monday to Friday, one per day. Clues: A is on call earlier in the week than C. D is on call the day immediately after B. E is on call on Wednesday. A is not on call on Monday."},"stem":"Using the same rota, on which day is C on call?","format":"single_best","options":["Tuesday","Thursday","Monday","Friday"],"answer":3,"explanation":"With B Monday, D Tuesday, E Wednesday, the remaining days Thursday and Friday go to A and C, and A is earlier than C, so A is Thursday and C is Friday.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-009","subtest":"decision_making","type":"logical_puzzle","stimulusId":"ucat-dm-pz1","stimulus":{"kind":"text","content":"Five doctors (A, B, C, D, E) are each on call on exactly one day from Monday to Friday, one per day. Clues: A is on call earlier in the week than C. D is on call the day immediately after B. E is on call on Wednesday. A is not on call on Monday."},"stem":"Using the same rota, which statement must be true?","format":"single_best","options":["A is on call the day immediately before C.","B is on call after E.","D is on call on Friday.","C is on call before E."],"answer":0,"explanation":"The unique solution is B Mon, D Tue, E Wed, A Thu, C Fri. A (Thursday) is immediately before C (Friday); the other statements are false in that order.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-010","subtest":"decision_making","type":"logical_puzzle","stimulusId":"ucat-dm-pz2","stimulus":{"kind":"text","content":"Four friends (Will, Xena, Yusuf, Zoe) each ordered a different drink: tea, coffee, juice, water. Will did not order tea or coffee. Xena ordered coffee. Yusuf did not order juice. Each drink was ordered by exactly one person."},"stem":"What did Will order?","format":"single_best","options":["Tea","Juice or water","Coffee","Only juice"],"answer":1,"explanation":"Will avoids tea and coffee, and Xena took coffee, so Will had juice or water. The clues do not pin which, so 'juice or water' is the only certain answer.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-011","subtest":"decision_making","type":"logical_puzzle","stimulusId":"ucat-dm-pz2","stimulus":{"kind":"text","content":"Four friends (Will, Xena, Yusuf, Zoe) each ordered a different drink: tea, coffee, juice, water. Will did not order tea or coffee. Xena ordered coffee. Yusuf did not order juice. Each drink was ordered by exactly one person."},"stem":"What did Yusuf order?","format":"single_best","options":["Juice","Coffee","Tea or water","Only tea"],"answer":2,"explanation":"Coffee is Xena's and Yusuf avoids juice, so Yusuf had tea or water. Without more, it cannot be narrowed further.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-012","subtest":"decision_making","type":"logical_puzzle","stimulusId":"ucat-dm-pz2","stimulus":{"kind":"text","content":"Four friends (Will, Xena, Yusuf, Zoe) each ordered a different drink: tea, coffee, juice, water. Will did not order tea or coffee. Xena ordered coffee. Yusuf did not order juice. Each drink was ordered by exactly one person."},"stem":"If Yusuf ordered water, what did Zoe order?","format":"single_best","options":["Juice","Coffee","Water","Tea"],"answer":3,"explanation":"If Yusuf had water, then Will (juice or water) must take juice. Coffee is Xena's, so the remaining drink, tea, goes to Zoe.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-013","subtest":"decision_making","type":"logical_puzzle","stimulusId":"ucat-dm-pz3","stimulus":{"kind":"text","content":"Three boxes are labelled 'Apples', 'Oranges' and 'Mixed'. Every label is wrong. You may draw one fruit, without looking inside, from a single box of your choice to work out the true contents of all three boxes."},"stem":"From which box should you draw to guarantee you can deduce all three?","format":"single_best","options":["the box labelled 'Mixed'","the box labelled 'Apples'","the box labelled 'Oranges'","it is impossible to guarantee"],"answer":0,"explanation":"Since every label is wrong, the 'Mixed' box is purely apples or purely oranges. Drawing one fruit from it reveals its true single type; the other two then follow because their labels are also wrong.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-014","subtest":"decision_making","type":"logical_puzzle","stimulusId":"ucat-dm-pz3","stimulus":{"kind":"text","content":"Three boxes are labelled 'Apples', 'Oranges' and 'Mixed'. Every label is wrong. You may draw one fruit, without looking inside, from a single box of your choice to work out the true contents of all three boxes."},"stem":"You draw from the 'Mixed' box and get an apple. What are the true contents of the box labelled 'Oranges'?","format":"single_best","options":["Apples","Mixed","Oranges","Cannot be determined"],"answer":1,"explanation":"The 'Mixed' box is actually Apples. The box labelled 'Oranges' cannot be oranges (label wrong) and cannot be apples (already placed), so it is Mixed.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-015","subtest":"decision_making","type":"logical_puzzle","stimulusId":"ucat-dm-pz4","stimulus":{"kind":"text","content":"In a row of five houses numbered 1 to 5 from left to right, live a teacher, a nurse, an engineer, a chef and a pilot. The nurse lives at number 3. The engineer lives immediately to the right of the teacher. The chef lives at number 1. The pilot does not live at number 5."},"stem":"Who lives at house number 5?","format":"single_best","options":["The pilot","The teacher","The engineer","The nurse"],"answer":2,"explanation":"Chef is 1, nurse is 3. The teacher-engineer pair must be adjacent; the only adjacent free pair is 4 and 5, so teacher is 4 and engineer is 5. The pilot then takes 2 (and is not at 5, consistent).","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-016","subtest":"decision_making","type":"venn_diagram","stimulusId":null,"stem":"In a group of 120 students, 70 study French, 55 study German, and 25 study both. How many study neither language?","format":"single_best","options":["45","30","0","20"],"answer":3,"explanation":"Studying at least one = 70 + 55 - 25 = 100, so neither = 120 - 100 = 20.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-017","subtest":"decision_making","type":"venn_diagram","stimulusId":null,"stem":"In a survey of 200 people, 90 read newspaper X, 80 read Y and 70 read Z. 30 read both X and Y, 25 read Y and Z, 20 read X and Z, and 10 read all three. How many read none of the three?","format":"single_best","options":["25","35","40","15"],"answer":0,"explanation":"Union = 90 + 80 + 70 - 30 - 25 - 20 + 10 = 175. None = 200 - 175 = 25.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-018","subtest":"decision_making","type":"venn_diagram","stimulusId":null,"stem":"Using the same survey (200 people; X 90, Y 80, Z 70; X and Y 30, Y and Z 25, X and Z 20, all three 10), how many read exactly one of the three newspapers?","format":"single_best","options":["175","120","30","90"],"answer":1,"explanation":"Only X = 90 - 30 - 20 + 10 = 50; only Y = 80 - 30 - 25 + 10 = 35; only Z = 70 - 25 - 20 + 10 = 35. Exactly one = 50 + 35 + 35 = 120.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-019","subtest":"decision_making","type":"venn_diagram","stimulusId":null,"stem":"Every student in a class of 40 plays at least one of football or hockey. 28 play football and 19 play hockey. How many play both?","format":"single_best","options":["9","11","7","12"],"answer":2,"explanation":"Since everyone plays at least one, 28 + 19 - both = 40, so both = 47 - 40 = 7.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-020","subtest":"decision_making","type":"venn_diagram","stimulusId":null,"stem":"In a clinic audit of 150 patients, 95 had a blood test, 60 had an X-ray, and 40 had both. How many had a blood test but not an X-ray?","format":"single_best","options":["95","20","60","55"],"answer":3,"explanation":"Blood test only = 95 - 40 (the both group) = 55.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-021","subtest":"decision_making","type":"probabilistic_reasoning","stimulusId":null,"stem":"A bag holds 5 red, 4 blue and 3 green counters (12 total). Two are drawn at random without replacement. What is the probability that both are red?","format":"single_best","options":["5/33","25/144","5/12","1/6"],"answer":0,"explanation":"P(both red) = (5/12) x (4/11) = 20/132 = 5/33. The value 25/144 wrongly assumes replacement.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-022","subtest":"decision_making","type":"probabilistic_reasoning","stimulusId":null,"stem":"From the same bag (5 red, 4 blue, 3 green; 12 total), two counters are drawn without replacement. What is the probability that at least one is blue?","format":"single_best","options":["14/33","19/33","1/3","2/3"],"answer":1,"explanation":"P(no blue) = (8/12) x (7/11) = 56/132 = 14/33. So P(at least one blue) = 1 - 14/33 = 19/33.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-023","subtest":"decision_making","type":"probabilistic_reasoning","stimulusId":null,"stem":"Two fair six-sided dice are rolled. What is the probability that the two numbers sum to 8?","format":"single_best","options":["1/8","1/6","5/36","7/36"],"answer":2,"explanation":"The pairs summing to 8 are (2,6),(3,5),(4,4),(5,3),(6,2): 5 of 36 equally likely outcomes, so 5/36.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-024","subtest":"decision_making","type":"probabilistic_reasoning","stimulusId":null,"stem":"A test correctly flags a condition 90% of the time. Two independent people who both have the condition are tested. What is the probability that the test flags both?","format":"single_best","options":["9/10","99/100","9/20","81/100"],"answer":3,"explanation":"Independent events multiply: 0.9 x 0.9 = 0.81 = 81/100.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-025","subtest":"decision_making","type":"probabilistic_reasoning","stimulusId":null,"stem":"A spinner has 8 equal sectors numbered 1 to 8. It is spun once. What is the probability the result is a prime number?","format":"single_best","options":["1/2","3/8","5/8","1/4"],"answer":0,"explanation":"Primes from 1 to 8 are 2, 3, 5, 7: that is 4 of 8 outcomes, so 4/8 = 1/2.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-026","subtest":"decision_making","type":"probabilistic_reasoning","stimulusId":null,"stem":"In a class, 60% of students study biology and, of those, 25% also study chemistry. A student is chosen at random. What is the probability the student studies both biology and chemistry?","format":"single_best","options":["1/4","3/20","17/20","7/20"],"answer":1,"explanation":"P(both) = P(biology) x P(chemistry given biology) = 0.60 x 0.25 = 0.15 = 15/100 = 3/20.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-027","subtest":"decision_making","type":"probabilistic_reasoning","stimulusId":null,"stem":"A bag has 3 white and 7 black balls. One ball is drawn, its colour noted, and it is returned; then a second is drawn. What is the probability both draws are white?","format":"single_best","options":["1/15","3/5","9/100","3/10"],"answer":2,"explanation":"With replacement the draws are independent: (3/10) x (3/10) = 9/100.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-028","subtest":"decision_making","type":"probabilistic_reasoning","stimulusId":null,"stem":"The probability it rains on any given day in a region is 0.2, independently each day. What is the probability it does not rain on either of two consecutive days?","format":"single_best","options":["2/5","1/25","24/25","16/25"],"answer":3,"explanation":"P(no rain on a day) = 0.8; for two independent days, 0.8 x 0.8 = 0.64 = 64/100 = 16/25.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-029","subtest":"decision_making","type":"recognising_assumptions","stimulusId":null,"stem":"A manager argues: 'Our advertising campaign worked, because sales rose 10% the month it ran.' Which is the strongest objection to this reasoning?","format":"single_best","options":["Sales may have risen for other reasons, such as seasonal demand, rather than the campaign.","The campaign was expensive to produce.","Sales figures are always unreliable.","Advertising is generally a good idea."],"answer":0,"explanation":"The argument assumes the campaign caused the rise. The strongest objection points to an alternative cause (for example seasonality), which would undercut the causal claim.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-030","subtest":"decision_making","type":"recognising_assumptions","stimulusId":null,"stem":"Argument: 'We should fund more streetlights, because well-lit streets reduce crime.' Which assumption does the argument most rely on?","format":"single_best","options":["Streetlights are attractive to look at.","The crime the lights reduce would not simply move elsewhere.","Crime is the only problem the town faces.","Everyone supports the proposal."],"answer":1,"explanation":"If lighting merely displaces crime to other areas, the funding would not reduce overall crime; the argument assumes the reduction is real rather than displaced.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-031","subtest":"decision_making","type":"recognising_assumptions","stimulusId":null,"stem":"Which of the following, if true, would most weaken the claim 'Students who eat breakfast score higher on tests, so schools should provide free breakfast to raise scores'?","format":"single_best","options":["Breakfast foods vary in nutritional value.","Some students dislike eating early in the morning.","Students who eat breakfast tend to come from households that also support study in many other ways.","Free breakfast would be popular with parents."],"answer":2,"explanation":"If breakfast-eaters differ systematically in other supportive ways, the score gap may be caused by those factors, not breakfast, weakening the causal claim behind the policy.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-032","subtest":"decision_making","type":"recognising_assumptions","stimulusId":null,"stem":"A columnist writes: 'Country A has lower average taxes than Country B and faster economic growth. Therefore lower taxes cause faster growth.' The main flaw in this reasoning is that it:","format":"single_best","options":["uses figures that are too precise","fails to define the word economy","assumes both countries are the same size","draws a causal conclusion from a single comparison that ignores other differences"],"answer":3,"explanation":"Two countries differ in countless ways. Inferring causation from one paired comparison, ignoring confounders, is the central flaw.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-033","subtest":"decision_making","type":"recognising_assumptions","stimulusId":null,"stem":"Statement: 'No serious side effects were reported in the trial, so the drug is safe for everyone.' Which best identifies the weakness?","format":"single_best","options":["A trial sample may be too small or unrepresentative to reveal rare effects across the whole population.","The drug was probably expensive to develop.","Trials are never useful.","Side effects are impossible to measure."],"answer":0,"explanation":"Absence of reported effects in a limited trial does not establish safety for everyone; rare or subgroup effects may not appear in a small or unrepresentative sample.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-034","subtest":"decision_making","type":"interpreting_information","stimulusId":"ucat-dm-info1","stimulus":{"kind":"table","content":"<table><thead><tr><th>Plan</th><th>Monthly fee</th><th>Included data</th><th>Extra per GB</th></tr></thead><tbody><tr><th scope=\"row\">Basic</th><td>$20</td><td>5 GB</td><td>$8</td></tr><tr><th scope=\"row\">Plus</th><td>$35</td><td>20 GB</td><td>$5</td></tr><tr><th scope=\"row\">Max</th><td>$55</td><td>Unlimited</td><td>n/a</td></tr></tbody></table>","caption":"Mobile plans"},"stem":"Using the table, a user expects to need 25 GB in a month. Which plan is cheapest for that usage?","format":"single_best","options":["Plus","Max","Basic","Basic and Plus cost the same"],"answer":1,"explanation":"Basic: 20 + 8 x 20 = $180. Plus: 35 + 5 x 5 = $60. Max: $55 (unlimited). Max is cheapest at this usage.","difficulty":"hard","source":"original"},
  {"id":"ucat-dm-035","subtest":"decision_making","type":"interpreting_information","stimulusId":"ucat-dm-info1","stimulus":{"kind":"table","content":"<table><thead><tr><th>Plan</th><th>Monthly fee</th><th>Included data</th><th>Extra per GB</th></tr></thead><tbody><tr><th scope=\"row\">Basic</th><td>$20</td><td>5 GB</td><td>$8</td></tr><tr><th scope=\"row\">Plus</th><td>$35</td><td>20 GB</td><td>$5</td></tr><tr><th scope=\"row\">Max</th><td>$55</td><td>Unlimited</td><td>n/a</td></tr></tbody></table>","caption":"Mobile plans"},"stem":"Using the table, what does the Basic plan cost in a month using 12 GB of data?","format":"single_best","options":["$116","$96","$76","$70"],"answer":2,"explanation":"Basic includes 5 GB; the extra 7 GB cost 7 x $8 = $56, plus the $20 fee = $76.","difficulty":"medium","source":"original"},
  {"id":"ucat-dm-036","subtest":"decision_making","type":"interpreting_information","stimulusId":"ucat-dm-info1","stimulus":{"kind":"table","content":"<table><thead><tr><th>Plan</th><th>Monthly fee</th><th>Included data</th><th>Extra per GB</th></tr></thead><tbody><tr><th scope=\"row\">Basic</th><td>$20</td><td>5 GB</td><td>$8</td></tr><tr><th scope=\"row\">Plus</th><td>$35</td><td>20 GB</td><td>$5</td></tr><tr><th scope=\"row\">Max</th><td>$55</td><td>Unlimited</td><td>n/a</td></tr></tbody></table>","caption":"Mobile plans"},"stem":"Using the table, how much does the Plus plan cost in a month with 32 GB of data used?","format":"single_best","options":["$60","$35","$160","$95"],"answer":3,"explanation":"Plus includes 20 GB; the extra 12 GB cost 12 x $5 = $60, plus the $35 fee = $95.","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-001","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d1","stimulus":{"kind":"table","content":"<table><thead><tr><th>Product</th><th>Units</th><th>Price</th><th>Cost</th></tr></thead><tbody><tr><th scope=\"row\">Alpha</th><td>120</td><td>$25</td><td>$18</td></tr><tr><th scope=\"row\">Beta</th><td>80</td><td>$40</td><td>$30</td></tr><tr><th scope=\"row\">Gamma</th><td>200</td><td>$12</td><td>$9</td></tr><tr><th scope=\"row\">Delta</th><td>150</td><td>$30</td><td>$22</td></tr></tbody></table>","caption":"Last month's sales (profit per unit = price minus cost)"},"stem":"What was the total profit from Delta last month?","format":"single_best","options":["$1,200","$4,478","$960","$3,300"],"answer":0,"explanation":"Delta profit per unit = 30 - 22 = $8; total = 8 x 150 = $1,200.","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-002","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d1","stimulus":{"kind":"table","content":"<table><thead><tr><th>Product</th><th>Units</th><th>Price</th><th>Cost</th></tr></thead><tbody><tr><th scope=\"row\">Alpha</th><td>120</td><td>$25</td><td>$18</td></tr><tr><th scope=\"row\">Beta</th><td>80</td><td>$40</td><td>$30</td></tr><tr><th scope=\"row\">Gamma</th><td>200</td><td>$12</td><td>$9</td></tr><tr><th scope=\"row\">Delta</th><td>150</td><td>$30</td><td>$22</td></tr></tbody></table>","caption":"Last month's sales (profit per unit = price minus cost)"},"stem":"Which product generated the greatest total profit?","format":"single_best","options":["Alpha","Delta","Beta","Gamma"],"answer":1,"explanation":"Alpha 7 x 120 = $840; Beta 10 x 80 = $800; Gamma 3 x 200 = $600; Delta 8 x 150 = $1,200. Delta is greatest.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-003","subtest":"quantitative_reasoning","type":"percentages","stimulusId":"ucat-qr-d1","stimulus":{"kind":"table","content":"<table><thead><tr><th>Product</th><th>Units</th><th>Price</th><th>Cost</th></tr></thead><tbody><tr><th scope=\"row\">Alpha</th><td>120</td><td>$25</td><td>$18</td></tr><tr><th scope=\"row\">Beta</th><td>80</td><td>$40</td><td>$30</td></tr><tr><th scope=\"row\">Gamma</th><td>200</td><td>$12</td><td>$9</td></tr><tr><th scope=\"row\">Delta</th><td>150</td><td>$30</td><td>$22</td></tr></tbody></table>","caption":"Last month's sales (profit per unit = price minus cost)"},"stem":"If Beta's price rises 15% and its unit sales fall 20% (cost unchanged), what is Beta's new total profit?","format":"single_best","options":["$2,944","$800","$1,024","$1,280"],"answer":2,"explanation":"New price 40 x 1.15 = $46, profit per unit 46 - 30 = $16; new units 80 x 0.8 = 64; total 16 x 64 = $1,024.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-004","subtest":"quantitative_reasoning","type":"percentages","stimulusId":"ucat-qr-d1","stimulus":{"kind":"table","content":"<table><thead><tr><th>Product</th><th>Units</th><th>Price</th><th>Cost</th></tr></thead><tbody><tr><th scope=\"row\">Alpha</th><td>120</td><td>$25</td><td>$18</td></tr><tr><th scope=\"row\">Beta</th><td>80</td><td>$40</td><td>$30</td></tr><tr><th scope=\"row\">Gamma</th><td>200</td><td>$12</td><td>$9</td></tr><tr><th scope=\"row\">Delta</th><td>150</td><td>$30</td><td>$22</td></tr></tbody></table>","caption":"Last month's sales (profit per unit = price minus cost)"},"stem":"Across all four products, what percentage of total revenue did Gamma's revenue represent? (Give to the nearest whole percent.)","format":"single_best","options":["14%","36%","11%","18%"],"answer":3,"explanation":"Revenues: Alpha 3,000; Beta 3,200; Gamma 2,400; Delta 4,500; total 13,100. Gamma share = 2,400/13,100 = 18.3%, about 18%.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-005","subtest":"quantitative_reasoning","type":"percentages","stimulusId":null,"stem":"After a 12% discount, a coat sells for $176. What was the original price?","format":"single_best","options":["$200","$197.12","$154.88","$188"],"answer":0,"explanation":"The sale price is 88% of the original, so original = 176 / 0.88 = $200.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-006","subtest":"quantitative_reasoning","type":"percentages","stimulusId":null,"stem":"A price rises from $80 to $100. What is the percentage increase?","format":"single_best","options":["20%","25%","125%","80%"],"answer":1,"explanation":"Increase = 20 on a base of 80, so 20/80 = 25%.","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-007","subtest":"quantitative_reasoning","type":"percentages","stimulusId":null,"stem":"A value falls by 20% and then rises by 20%. Compared with the start, the final value is:","format":"single_best","options":["unchanged","4% higher","4% lower","2% lower"],"answer":2,"explanation":"0.8 x 1.2 = 0.96, a net fall of 4%. Successive percentage changes do not cancel.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-008","subtest":"quantitative_reasoning","type":"percentages","stimulusId":null,"stem":"A laptop costs $1,200 before tax. Tax of 10% is added, then a loyalty discount of 5% is applied to the taxed price. What is the final price?","format":"single_best","options":["$1,260","$1,380","$1,315","$1,254"],"answer":3,"explanation":"Taxed price 1,200 x 1.10 = $1,320; after 5% off, 1,320 x 0.95 = $1,254.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-009","subtest":"quantitative_reasoning","type":"ratios_proportion","stimulusId":null,"stem":"A 1.5 kg batch uses flour, sugar and butter in the ratio 5:3:2 by weight. How much butter is needed?","format":"single_best","options":["300 g","450 g","750 g","200 g"],"answer":0,"explanation":"Total parts 5 + 3 + 2 = 10; butter is 2 parts = 2/10 x 1,500 g = 300 g.","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-010","subtest":"quantitative_reasoning","type":"ratios_proportion","stimulusId":null,"stem":"Two investors share a $42,000 profit in the ratio 4:3. How much more does the larger share receive than the smaller?","format":"single_best","options":["$24,000","$6,000","$21,000","$18,000"],"answer":1,"explanation":"One part = 42,000 / 7 = $6,000; the difference is 1 part = $6,000.","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-011","subtest":"quantitative_reasoning","type":"ratios_proportion","stimulusId":null,"stem":"A map uses a scale of 1:25,000. Two towns are 14 cm apart on the map. What is the real distance in kilometres?","format":"single_best","options":["350,000 km","350 km","3.5 km","0.001 km"],"answer":2,"explanation":"Real distance = 14 cm x 25,000 = 350,000 cm = 3,500 m = 3.5 km.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-012","subtest":"quantitative_reasoning","type":"ratios_proportion","stimulusId":null,"stem":"A recipe for 4 people needs 320 g of rice. Keeping the proportion, how much rice is needed for 7 people?","format":"single_best","options":["280 g","327 g","182.857 g","560 g"],"answer":3,"explanation":"Per person 320 / 4 = 80 g; for 7 people 80 x 7 = 560 g.","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-013","subtest":"quantitative_reasoning","type":"rates","stimulusId":null,"stem":"A car travels 150 km in 2 hours 30 minutes. What is its average speed in km/h?","format":"single_best","options":["60 km/h","75 km/h","50 km/h","375 km/h"],"answer":0,"explanation":"2 hours 30 minutes = 2.5 hours; speed = 150 / 2.5 = 60 km/h.","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-014","subtest":"quantitative_reasoning","type":"rates","stimulusId":null,"stem":"A tap fills a 90-litre tank in 6 minutes. What is the flow rate in litres per second?","format":"single_best","options":["15 L/s","0.25 L/s","1.5 L/s","0.067 L/s"],"answer":1,"explanation":"6 minutes = 360 seconds; rate = 90 / 360 = 0.25 litres per second.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-015","subtest":"quantitative_reasoning","type":"rates","stimulusId":null,"stem":"One nurse can process 9 admissions per hour and another 6 per hour. Working together, how long to process 50 admissions? (Give to the nearest minute.)","format":"single_best","options":["333 minutes","500 minutes","200 minutes","50 minutes"],"answer":2,"explanation":"Combined rate 9 + 6 = 15 per hour; time = 50 / 15 hours = 3.33 hours = 200 minutes.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-016","subtest":"quantitative_reasoning","type":"rates","stimulusId":null,"stem":"A runner covers 8 km at 12 km/h. How many minutes does the run take?","format":"single_best","options":["0.667 minutes","90 minutes","96 minutes","40 minutes"],"answer":3,"explanation":"Time = distance / speed = 8 / 12 hours = 0.667 hours = 40 minutes.","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-017","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d5","stimulus":{"kind":"svg","content":"<svg viewBox=\"0 0 440 250\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"DM Sans, sans-serif\" font-size=\"12\"><line x1=\"18\" y1=\"198\" x2=\"428\" y2=\"198\" stroke=\"#94a3b8\" stroke-width=\"1\"/><rect x=\"42.3\" y=\"83.8\" width=\"54.0\" height=\"114.2\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"69.3\" y=\"77.8\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">42</text><text x=\"69.3\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q1</text><rect x=\"144.8\" y=\"40.3\" width=\"54.0\" height=\"157.7\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"171.8\" y=\"34.3\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">58</text><text x=\"171.8\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q2</text><rect x=\"247.3\" y=\"100.1\" width=\"54.0\" height=\"97.9\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"274.3\" y=\"94.1\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">36</text><text x=\"274.3\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q3</text><rect x=\"349.8\" y=\"24.0\" width=\"54.0\" height=\"174.0\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"376.8\" y=\"18.0\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">64</text><text x=\"376.8\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q4</text><text x=\"18\" y=\"16\" fill=\"#64748b\">Revenue ($000)</text></svg>","caption":"Quarterly revenue, in thousands of dollars","alt":"Bar chart of quarterly revenue: Q1 42, Q2 58, Q3 36, Q4 64 thousand dollars"},"stem":"Using the chart, what was the total revenue for the year (in thousands of dollars)?","format":"single_best","options":["200","190","220","256"],"answer":0,"explanation":"Total = 42 + 58 + 36 + 64 = 200 (thousand dollars).","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-018","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d5","stimulus":{"kind":"svg","content":"<svg viewBox=\"0 0 440 250\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"DM Sans, sans-serif\" font-size=\"12\"><line x1=\"18\" y1=\"198\" x2=\"428\" y2=\"198\" stroke=\"#94a3b8\" stroke-width=\"1\"/><rect x=\"42.3\" y=\"83.8\" width=\"54.0\" height=\"114.2\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"69.3\" y=\"77.8\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">42</text><text x=\"69.3\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q1</text><rect x=\"144.8\" y=\"40.3\" width=\"54.0\" height=\"157.7\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"171.8\" y=\"34.3\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">58</text><text x=\"171.8\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q2</text><rect x=\"247.3\" y=\"100.1\" width=\"54.0\" height=\"97.9\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"274.3\" y=\"94.1\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">36</text><text x=\"274.3\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q3</text><rect x=\"349.8\" y=\"24.0\" width=\"54.0\" height=\"174.0\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"376.8\" y=\"18.0\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">64</text><text x=\"376.8\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q4</text><text x=\"18\" y=\"16\" fill=\"#64748b\">Revenue ($000)</text></svg>","caption":"Quarterly revenue, in thousands of dollars","alt":"Bar chart of quarterly revenue: Q1 42, Q2 58, Q3 36, Q4 64 thousand dollars"},"stem":"Using the chart, the Q4 revenue was what percentage higher than Q3? (Nearest whole percent.)","format":"single_best","options":["44%","78%","28%","2%"],"answer":1,"explanation":"Increase = 64 - 36 = 28 on a base of 36; 28/36 = 77.8%, about 78%.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-019","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d5","stimulus":{"kind":"svg","content":"<svg viewBox=\"0 0 440 250\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"DM Sans, sans-serif\" font-size=\"12\"><line x1=\"18\" y1=\"198\" x2=\"428\" y2=\"198\" stroke=\"#94a3b8\" stroke-width=\"1\"/><rect x=\"42.3\" y=\"83.8\" width=\"54.0\" height=\"114.2\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"69.3\" y=\"77.8\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">42</text><text x=\"69.3\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q1</text><rect x=\"144.8\" y=\"40.3\" width=\"54.0\" height=\"157.7\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"171.8\" y=\"34.3\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">58</text><text x=\"171.8\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q2</text><rect x=\"247.3\" y=\"100.1\" width=\"54.0\" height=\"97.9\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"274.3\" y=\"94.1\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">36</text><text x=\"274.3\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q3</text><rect x=\"349.8\" y=\"24.0\" width=\"54.0\" height=\"174.0\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"376.8\" y=\"18.0\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">64</text><text x=\"376.8\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q4</text><text x=\"18\" y=\"16\" fill=\"#64748b\">Revenue ($000)</text></svg>","caption":"Quarterly revenue, in thousands of dollars","alt":"Bar chart of quarterly revenue: Q1 42, Q2 58, Q3 36, Q4 64 thousand dollars"},"stem":"Using the chart, what was the mean quarterly revenue (in thousands of dollars)?","format":"single_best","options":["58","64","50","36"],"answer":2,"explanation":"Mean = 200 / 4 = 50 (thousand dollars).","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-020","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d5","stimulus":{"kind":"svg","content":"<svg viewBox=\"0 0 440 250\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"DM Sans, sans-serif\" font-size=\"12\"><line x1=\"18\" y1=\"198\" x2=\"428\" y2=\"198\" stroke=\"#94a3b8\" stroke-width=\"1\"/><rect x=\"42.3\" y=\"83.8\" width=\"54.0\" height=\"114.2\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"69.3\" y=\"77.8\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">42</text><text x=\"69.3\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q1</text><rect x=\"144.8\" y=\"40.3\" width=\"54.0\" height=\"157.7\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"171.8\" y=\"34.3\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">58</text><text x=\"171.8\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q2</text><rect x=\"247.3\" y=\"100.1\" width=\"54.0\" height=\"97.9\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"274.3\" y=\"94.1\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">36</text><text x=\"274.3\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q3</text><rect x=\"349.8\" y=\"24.0\" width=\"54.0\" height=\"174.0\" fill=\"#0ea5e9\" rx=\"3\"/><text x=\"376.8\" y=\"18.0\" text-anchor=\"middle\" fill=\"#0a1628\" font-weight=\"700\">64</text><text x=\"376.8\" y=\"216\" text-anchor=\"middle\" fill=\"#334155\">Q4</text><text x=\"18\" y=\"16\" fill=\"#64748b\">Revenue ($000)</text></svg>","caption":"Quarterly revenue, in thousands of dollars","alt":"Bar chart of quarterly revenue: Q1 42, Q2 58, Q3 36, Q4 64 thousand dollars"},"stem":"If Q1 of the following year is forecast to be 25% above this year's Q4, what is the forecast (in thousands of dollars)?","format":"single_best","options":["52.5","89","48","80"],"answer":3,"explanation":"Forecast = 64 x 1.25 = 80 (thousand dollars).","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-021","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d6","stimulus":{"kind":"table","content":"<table><thead><tr><th>Taxable income</th><th>Rate on income in band</th></tr></thead><tbody><tr><th scope=\"row\">$0 to $18,200</th><td>0%</td></tr><tr><th scope=\"row\">$18,201 to $45,000</th><td>19%</td></tr><tr><th scope=\"row\">$45,001 to $120,000</th><td>32.5%</td></tr><tr><th scope=\"row\">Above $120,000</th><td>37%</td></tr></tbody></table>","caption":"Simplified marginal income tax bands"},"stem":"Using the bands, how much tax is owed on a taxable income of $45,000?","format":"single_best","options":["$5,092","$8,550","$14,625","$8,710"],"answer":0,"explanation":"Only income from $18,201 to $45,000 is taxed, at 19%: 0.19 x (45,000 - 18,200) = 0.19 x 26,800 = $5,092.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-022","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d6","stimulus":{"kind":"table","content":"<table><thead><tr><th>Taxable income</th><th>Rate on income in band</th></tr></thead><tbody><tr><th scope=\"row\">$0 to $18,200</th><td>0%</td></tr><tr><th scope=\"row\">$18,201 to $45,000</th><td>19%</td></tr><tr><th scope=\"row\">$45,001 to $120,000</th><td>32.5%</td></tr><tr><th scope=\"row\">Above $120,000</th><td>37%</td></tr></tbody></table>","caption":"Simplified marginal income tax bands"},"stem":"Using the bands, how much tax is owed on a taxable income of $60,000?","format":"single_best","options":["$19,500","$9,967","$13,585","$11,400"],"answer":1,"explanation":"First band: 0.19 x 26,800 = 5,092. Next: 0.325 x (60,000 - 45,000) = 0.325 x 15,000 = 4,875. Total = $9,967.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-023","subtest":"quantitative_reasoning","type":"percentages","stimulusId":"ucat-qr-d6","stimulus":{"kind":"table","content":"<table><thead><tr><th>Taxable income</th><th>Rate on income in band</th></tr></thead><tbody><tr><th scope=\"row\">$0 to $18,200</th><td>0%</td></tr><tr><th scope=\"row\">$18,201 to $45,000</th><td>19%</td></tr><tr><th scope=\"row\">$45,001 to $120,000</th><td>32.5%</td></tr><tr><th scope=\"row\">Above $120,000</th><td>37%</td></tr></tbody></table>","caption":"Simplified marginal income tax bands"},"stem":"For the $60,000 earner, what is the overall (effective) tax rate, to the nearest whole percent?","format":"single_best","options":["33%","32%","17%","19%"],"answer":2,"explanation":"Total tax $9,967 on $60,000 = 16.6%, about 17%. The 32.5% figure is only the top marginal rate, not the effective rate.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-024","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d6","stimulus":{"kind":"table","content":"<table><thead><tr><th>Taxable income</th><th>Rate on income in band</th></tr></thead><tbody><tr><th scope=\"row\">$0 to $18,200</th><td>0%</td></tr><tr><th scope=\"row\">$18,201 to $45,000</th><td>19%</td></tr><tr><th scope=\"row\">$45,001 to $120,000</th><td>32.5%</td></tr><tr><th scope=\"row\">Above $120,000</th><td>37%</td></tr></tbody></table>","caption":"Simplified marginal income tax bands"},"stem":"How much more tax is owed on $130,000 than on $120,000?","format":"single_best","options":["$3,250","$9,100","$3,800","$3,700"],"answer":3,"explanation":"Income from 120,000 to 130,000 is taxed at 37%: 0.37 x 10,000 = $3,700.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-025","subtest":"quantitative_reasoning","type":"percentages","stimulusId":null,"stem":"$2,000 is invested at 5% compound interest per year. What is it worth after 2 years?","format":"single_best","options":["$2,205","$2,200","$2,100","$2,210"],"answer":0,"explanation":"After 2 years: 2,000 x 1.05^2 = 2,000 x 1.1025 = $2,205.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-026","subtest":"quantitative_reasoning","type":"percentages","stimulusId":null,"stem":"A town's population of 50,000 grows by 4% in year one and 6% in year two. What is the population after two years? (Nearest whole number.)","format":"single_best","options":["55,000","55,120","55,125","54,000"],"answer":1,"explanation":"50,000 x 1.04 x 1.06 = 50,000 x 1.1024 = 55,120.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-027","subtest":"quantitative_reasoning","type":"percentages","stimulusId":null,"stem":"A machine loses 10% of its value each year (compound). What is a $8,000 machine worth after 3 years? (Nearest dollar.)","format":"single_best","options":["$5,600","$7,200","$5,832","$5,840"],"answer":2,"explanation":"8,000 x 0.9^3 = 8,000 x 0.729 = $5,832. Subtracting 30% directly would wrongly give $5,600.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-028","subtest":"quantitative_reasoning","type":"percentages","stimulusId":null,"stem":"An investment grows from $4,000 to $4,410 over two years at a constant annual compound rate. What is that annual rate?","format":"single_best","options":["10%","10.25%","5.50%","5%"],"answer":3,"explanation":"Growth factor = 4,410 / 4,000 = 1.1025; annual factor = sqrt(1.1025) = 1.05, so the rate is 5%.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-029","subtest":"quantitative_reasoning","type":"rates","stimulusId":"ucat-qr-d8","stimulus":{"kind":"text","content":"A medicine is dosed at 6 mg per kilogram of body weight per day, divided into 3 equal doses. It is supplied as a syrup containing 40 mg per 5 mL."},"stem":"Using the dosing rule, what is the total daily dose for a 25 kg child?","format":"single_best","options":["150 mg","50 mg","1,000 mg","31 mg"],"answer":0,"explanation":"Daily dose = 6 mg/kg x 25 kg = 150 mg.","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-030","subtest":"quantitative_reasoning","type":"rates","stimulusId":"ucat-qr-d8","stimulus":{"kind":"text","content":"A medicine is dosed at 6 mg per kilogram of body weight per day, divided into 3 equal doses. It is supplied as a syrup containing 40 mg per 5 mL."},"stem":"For the same 25 kg child, how many mg are in each of the 3 daily doses?","format":"single_best","options":["150 mg","50 mg","75 mg","25 mg"],"answer":1,"explanation":"Total 150 mg divided into 3 doses = 50 mg per dose.","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-031","subtest":"quantitative_reasoning","type":"rates","stimulusId":"ucat-qr-d8","stimulus":{"kind":"text","content":"A medicine is dosed at 6 mg per kilogram of body weight per day, divided into 3 equal doses. It is supplied as a syrup containing 40 mg per 5 mL."},"stem":"Using the syrup (40 mg per 5 mL), what volume delivers one 50 mg dose?","format":"single_best","options":["400 mL","1.25 mL","6.25 mL","5 mL"],"answer":2,"explanation":"Concentration 40 mg per 5 mL = 8 mg/mL; 50 mg / 8 mg/mL = 6.25 mL.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-032","subtest":"quantitative_reasoning","type":"rates","stimulusId":"ucat-qr-d8","stimulus":{"kind":"text","content":"A medicine is dosed at 6 mg per kilogram of body weight per day, divided into 3 equal doses. It is supplied as a syrup containing 40 mg per 5 mL."},"stem":"How many full days will a 300 mL bottle of the syrup last for the 25 kg child (150 mg/day)?","format":"single_best","options":["2 days","48 days","20 days","16 days"],"answer":3,"explanation":"Daily volume = 150 mg / 8 mg per mL = 18.75 mL. 300 / 18.75 = 16 days exactly.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-033","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d9","stimulus":{"kind":"table","content":"<table><thead><tr><th>Clinic</th><th>Seen on time</th><th>Delayed</th><th>Total</th></tr></thead><tbody><tr><th scope=\"row\">North</th><td>180</td><td>120</td><td>300</td></tr><tr><th scope=\"row\">South</th><td>210</td><td>90</td><td>300</td></tr><tr><th scope=\"row\">East</th><td>96</td><td>144</td><td>240</td></tr></tbody></table>","caption":"Patients seen on time vs delayed, last week"},"stem":"What percentage of North clinic's patients were seen on time?","format":"single_best","options":["60%","40%","21.43%","60.50%"],"answer":0,"explanation":"180 of 300 = 60%.","difficulty":"medium","source":"original"},
  {"id":"ucat-qr-034","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d9","stimulus":{"kind":"table","content":"<table><thead><tr><th>Clinic</th><th>Seen on time</th><th>Delayed</th><th>Total</th></tr></thead><tbody><tr><th scope=\"row\">North</th><td>180</td><td>120</td><td>300</td></tr><tr><th scope=\"row\">South</th><td>210</td><td>90</td><td>300</td></tr><tr><th scope=\"row\">East</th><td>96</td><td>144</td><td>240</td></tr></tbody></table>","caption":"Patients seen on time vs delayed, last week"},"stem":"Which clinic had the highest proportion of patients seen on time?","format":"single_best","options":["North","South","East","North and East were equal"],"answer":1,"explanation":"North 180/300 = 60%; South 210/300 = 70%; East 96/240 = 40%. South is highest.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-035","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d9","stimulus":{"kind":"table","content":"<table><thead><tr><th>Clinic</th><th>Seen on time</th><th>Delayed</th><th>Total</th></tr></thead><tbody><tr><th scope=\"row\">North</th><td>180</td><td>120</td><td>300</td></tr><tr><th scope=\"row\">South</th><td>210</td><td>90</td><td>300</td></tr><tr><th scope=\"row\">East</th><td>96</td><td>144</td><td>240</td></tr></tbody></table>","caption":"Patients seen on time vs delayed, last week"},"stem":"Across all three clinics combined, what percentage of patients were delayed? (Nearest whole percent.)","format":"single_best","options":["35%","40%","42%","50%"],"answer":2,"explanation":"Delayed = 120 + 90 + 144 = 354 of 840 total; 354/840 = 42.1%, about 42%.","difficulty":"hard","source":"original"},
  {"id":"ucat-qr-036","subtest":"quantitative_reasoning","type":"data_interpretation","stimulusId":"ucat-qr-d9","stimulus":{"kind":"table","content":"<table><thead><tr><th>Clinic</th><th>Seen on time</th><th>Delayed</th><th>Total</th></tr></thead><tbody><tr><th scope=\"row\">North</th><td>180</td><td>120</td><td>300</td></tr><tr><th scope=\"row\">South</th><td>210</td><td>90</td><td>300</td></tr><tr><th scope=\"row\">East</th><td>96</td><td>144</td><td>240</td></tr></tbody></table>","caption":"Patients seen on time vs delayed, last week"},"stem":"If East clinic improves so that the same number of patients (240) are seen with 75% on time, how many more patients would be seen on time than last week?","format":"single_best","options":["180","144","96","84"],"answer":3,"explanation":"75% of 240 = 180 on time; last week was 96; the increase is 180 - 96 = 84.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-001","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"Maya, a medical student, sees a nurse about to give a medication to the wrong patient. Proposed action: Maya immediately and calmly speaks up to stop the nurse before the medication is given. How appropriate is this action?","format":"rating_appropriate","answer":0,"explanation":"Patient safety overrides hierarchy and the risk is immediate, so speaking up at once is very appropriate even for a student.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-002","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"During a ward round, a consultant makes a small factual error about a guideline. Proposed action: Tom, a student, interrupts the round in front of the patient to correct the consultant. How appropriate is this action?","format":"rating_appropriate","answer":2,"explanation":"The error is minor and not an immediate safety risk, so a public interruption in front of the patient is inappropriate; raising it privately afterwards would be better. It is not the most extreme category because the underlying instinct to correct an error has some merit.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-003","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A fellow student asks Sara to sign him in to a compulsory teaching session he will miss. Proposed action: Sara signs him in as requested. How appropriate is this action?","format":"rating_appropriate","answer":3,"explanation":"Falsifying an attendance record is dishonest and a clear integrity breach, so this is very inappropriate.","difficulty":"easy","source":"original"},
  {"id":"ucat-sjt-004","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A patient tells Liam, a student, something in confidence and asks him not to record it, but it is clinically relevant. Proposed action: Liam reassures the patient, explains why the team needs to know, and encourages the patient to let him share it. How appropriate is this action?","format":"rating_appropriate","answer":0,"explanation":"Balancing the duty to share clinically relevant information with respect for the patient by explaining and seeking agreement is very appropriate.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-005","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"Priya, a student, is running a teaching session for juniors and realises she does not know the answer to a question. Proposed action: Priya admits she is unsure, and offers to find out and follow up. How appropriate is this action?","format":"rating_appropriate","answer":0,"explanation":"Honesty about the limits of your knowledge, with a commitment to follow up, models good practice and is very appropriate.","difficulty":"easy","source":"original"},
  {"id":"ucat-sjt-006","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A student notices a colleague seems persistently low and has mentioned feeling overwhelmed. Proposed action: The student quietly tells several others on the course so they can all keep an eye on him. How appropriate is this action?","format":"rating_appropriate","answer":2,"explanation":"The concern is caring, but spreading it to several others without consent breaches the colleague's privacy; speaking to the colleague directly or to a tutor would be better, so this is inappropriate rather than very inappropriate.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-007","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"Jack, a student, accidentally accesses the medical record of a relative out of curiosity, then realises he should not have. Proposed action: Jack says nothing, reasoning that no harm was done. How appropriate is this action?","format":"rating_appropriate","answer":3,"explanation":"Accessing records without a legitimate care reason is a serious confidentiality breach; concealing it compounds the error, so doing nothing is very inappropriate.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-008","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A patient offers Nadia, a student, a small box of chocolates to thank the team. Proposed action: Nadia politely accepts the chocolates on behalf of the team and shares them at the nurses' station. How appropriate is this action?","format":"rating_appropriate","answer":1,"explanation":"A small shared gift of thanks is generally acceptable, so this is appropriate rather than very appropriate, since judgement about gifts and local policy still applies.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-009","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"Omar, a student, is asked by a junior doctor to take blood from a patient, a procedure he has never performed unsupervised. Proposed action: Omar explains he has not done it unsupervised and asks for supervision first. How appropriate is this action?","format":"rating_appropriate","answer":0,"explanation":"Recognising the limits of competence and asking for supervision protects the patient and is very appropriate.","difficulty":"easy","source":"original"},
  {"id":"ucat-sjt-010","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A student sees a classmate copy answers during an online open-book quiz that is meant to be done alone. Proposed action: The student reports it anonymously to the course office. How appropriate is this action?","format":"rating_appropriate","answer":1,"explanation":"Reporting a genuine integrity breach is appropriate; speaking to the classmate first might be preferred by some, so it is appropriate rather than very appropriate.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-011","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"Ella, a student, disagrees with a senior's management plan but the senior has explained the reasoning and it is within accepted practice. Proposed action: Ella refuses to participate in the patient's care in protest. How appropriate is this action?","format":"rating_appropriate","answer":3,"explanation":"When a plan is within accepted practice and has been explained, refusing to participate abandons the patient and is very inappropriate; raising remaining concerns through discussion is the correct route.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-012","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A distressed patient asks Sam, a student, for his personal phone number to ask follow-up questions. Proposed action: Sam gives his personal number so the patient feels supported. How appropriate is this action?","format":"rating_appropriate","answer":3,"explanation":"Sharing personal contact details crosses a professional boundary and is very inappropriate; directing the patient to proper channels is the right approach.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-013","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"On placement, a student notices the sharps bin is dangerously overfull. Proposed action: The student informs a nurse straight away so it can be replaced. How appropriate is this action?","format":"rating_appropriate","answer":0,"explanation":"Acting promptly on an evident safety hazard by alerting the right person is very appropriate.","difficulty":"easy","source":"original"},
  {"id":"ucat-sjt-014","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A student is asked by a patient what is wrong with them, but the student does not yet know the diagnosis. Proposed action: The student gives a reassuring guess to put the patient at ease. How appropriate is this action?","format":"rating_appropriate","answer":3,"explanation":"Guessing a diagnosis risks giving false or harmful information; it is very inappropriate. Acknowledging uncertainty and directing the patient to the treating team is correct.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-015","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"Two students are assigned a joint project; one has done very little. Proposed action: The other student first speaks to him directly to understand why and agree a fair split before involving a tutor. How appropriate is this action?","format":"rating_appropriate","answer":0,"explanation":"Addressing the issue directly and fairly before escalating is a constructive, proportionate first step and is very appropriate.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-016","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A student smells alcohol on a colleague who is about to see patients. Proposed action: The student says nothing because he is not certain. How appropriate is this action?","format":"rating_appropriate","answer":3,"explanation":"A colleague possibly impaired before seeing patients is a serious safety risk; ignoring it is very inappropriate. The concern should be raised promptly with a supervisor even if uncertain.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-017","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A grateful patient's family offers a student a significant cash tip. Proposed action: The student declines politely and explains he cannot accept it. How appropriate is this action?","format":"rating_appropriate","answer":0,"explanation":"Declining a significant cash gift and explaining why maintains professional boundaries and is very appropriate.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-018","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A student realises she recorded an observation in the wrong patient's notes an hour ago. Proposed action: She quietly deletes what she can and says nothing to avoid embarrassment. How appropriate is this action?","format":"rating_appropriate","answer":3,"explanation":"Concealing a documentation error risks patient harm and is dishonest; it is very inappropriate. The error should be corrected transparently and the team informed.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-019","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"During a busy shift a nurse asks a student to chase an urgent result, which is within his ability. Proposed action: The student agrees and follows up promptly. How appropriate is this action?","format":"rating_appropriate","answer":0,"explanation":"Helping with a reasonable task within his competence during a busy shift is very appropriate.","difficulty":"easy","source":"original"},
  {"id":"ucat-sjt-020","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A student is unsure whether a senior's instruction is safe for a particular patient. Proposed action: The student carries it out anyway rather than question a senior. How appropriate is this action?","format":"rating_appropriate","answer":3,"explanation":"Acting on an instruction you believe may be unsafe, without checking, risks patient harm and is very inappropriate; the student should seek clarification first.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-021","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A classmate confides that she is struggling and asks the student not to tell anyone, but mentions thoughts of self-harm. Proposed action: The student encourages her to seek help and, given the risk, speaks to a tutor or support service even though she asked him not to. How appropriate is this action?","format":"rating_appropriate","answer":0,"explanation":"Where there is a risk of serious harm, the duty to protect a person's safety can outweigh a request for secrecy, so seeking help is very appropriate.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-022","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A student finds a ward computer left logged in under a doctor's account. Proposed action: The student logs it out and mentions it to the doctor so it does not happen again. How appropriate is this action?","format":"rating_appropriate","answer":0,"explanation":"Protecting confidential records by logging out and giving a quiet reminder is very appropriate.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-023","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A patient asks a student to help them leave the ward to smoke, against medical advice while on monitoring. Proposed action: The student helps them out so they are not distressed. How appropriate is this action?","format":"rating_appropriate","answer":3,"explanation":"Helping a monitored patient act against medical advice could endanger them and is very inappropriate; the student should explain and involve the nursing staff.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-024","subtest":"situational_judgement","type":"appropriateness_rating","stimulusId":null,"stem":"A student overhears two colleagues mocking a patient's accent in the corridor. Proposed action: The student tells them it is not acceptable and that it could be overheard. How appropriate is this action?","format":"rating_appropriate","answer":0,"explanation":"Challenging disrespectful behaviour towards a patient, calmly and directly, upholds professional standards and is very appropriate.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-025","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"A student is deciding how to respond after seeing a colleague post a photo from theatre that includes a patient's face. When deciding, how important is the following consideration: whether the patient gave consent for the image to be shared.","format":"rating_important","answer":0,"explanation":"Consent and patient confidentiality are central to whether the post is a breach, so this consideration is very important.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-026","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"In the same situation, how important is the following consideration: how many likes the post has already received.","format":"rating_important","answer":3,"explanation":"The popularity of the post has no bearing on the professional and confidentiality issues, so it is not important at all.","difficulty":"easy","source":"original"},
  {"id":"ucat-sjt-027","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"A student is unsure whether to raise a concern about a senior's repeated rudeness to patients. How important is the following consideration: the effect of the behaviour on patients' care and dignity.","format":"rating_important","answer":0,"explanation":"The impact on patients' care and dignity is central to whether and how to raise the concern, so it is very important.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-028","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"In the same situation, how important is the following consideration: whether raising it might make the senior dislike the student.","format":"rating_important","answer":2,"explanation":"Personal discomfort is understandable but should not be decisive when patient care is affected, so it is of minor importance rather than entirely irrelevant.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-029","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"A student must decide whether to perform a task a junior doctor has delegated. How important is the following consideration: whether the student has been trained and is competent to do it safely.","format":"rating_important","answer":0,"explanation":"Competence to perform the task safely is fundamental to patient safety, so it is very important.","difficulty":"easy","source":"original"},
  {"id":"ucat-sjt-030","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"In the same delegation situation, how important is the following consideration: whether saying no might seem unhelpful to the team.","format":"rating_important","answer":2,"explanation":"Appearing helpful matters a little to teamwork but must not override safe practice, so it is of minor importance.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-031","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"A student notices a medication chart that looks inconsistent. How important is the following consideration: confirming the discrepancy with the prescriber or pharmacist before acting.","format":"rating_important","answer":0,"explanation":"Verifying with the right professional prevents both errors and unnecessary alarm, so it is very important.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-032","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"In the same situation, how important is the following consideration: whether the student is near the end of their shift and keen to leave.","format":"rating_important","answer":3,"explanation":"A possible medication error must be addressed regardless of the time; the student's convenience is not important at all.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-033","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"A patient declines a student's involvement in their care. How important is the following consideration: respecting the patient's wishes about who is present.","format":"rating_important","answer":0,"explanation":"Patient autonomy includes choosing who participates in their care, so respecting this is very important.","difficulty":"easy","source":"original"},
  {"id":"ucat-sjt-034","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"In the same situation, how important is the following consideration: the student's need to complete a logbook requirement for the case.","format":"rating_important","answer":2,"explanation":"The logbook matters to the student's training but cannot override the patient's wishes, so it is of minor importance.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-035","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"A student is deciding whether to report that they made a minor error that caused no harm. How important is the following consideration: whether reporting could help prevent the same error by others.","format":"rating_important","answer":0,"explanation":"Learning and system improvement from near-misses is a key reason to report, so this is very important.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-036","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"In the same situation, how important is the following consideration: whether anyone else noticed the error.","format":"rating_important","answer":3,"explanation":"Whether others noticed should not determine honesty about an error, so it is not important at all.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-037","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"A colleague asks a student to cover the fact that the colleague left early. How important is the following consideration: the student's duty to be honest if asked directly.","format":"rating_important","answer":0,"explanation":"Professional honesty is a core duty, so it is very important when deciding how to respond.","difficulty":"medium","source":"original"},
  {"id":"ucat-sjt-038","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"In the same situation, how important is the following consideration: that the colleague is a close friend.","format":"rating_important","answer":2,"explanation":"Friendship is a real pull but should not override honesty and fairness, so it is of minor importance rather than irrelevant.","difficulty":"hard","source":"original"},
  {"id":"ucat-sjt-039","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"A student sees that a waiting patient appears increasingly unwell. How important is the following consideration: alerting a clinician promptly about the change.","format":"rating_important","answer":0,"explanation":"A patient deteriorating while waiting is a safety matter, so prompt escalation is very important.","difficulty":"easy","source":"original"},
  {"id":"ucat-sjt-040","subtest":"situational_judgement","type":"importance_rating","stimulusId":null,"stem":"In the same situation, how important is the following consideration: whether telling staff might be seen as overstepping the student role.","format":"rating_important","answer":2,"explanation":"Concern about overstepping is understandable but should not delay raising a genuine safety issue, so it is of minor importance.","difficulty":"hard","source":"original"}
];
